export enum AspectRatio {
  Square = "1:1",
  Portrait = "3:4",
  Landscape = "4:3",
  WidePortrait = "9:16",
  WideLandscape = "16:9"
}

export enum ImageSize {
  OneK = "1K",
  TwoK = "2K",
  FourK = "4K"
}

export interface GenerationConfig {
  aspectRatio: AspectRatio;
  imageSize: ImageSize;
  batchSize: number;
}

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  config: GenerationConfig;
  timestamp: number;
}

export interface GenerationSession {
  id: string;
  prompt: string;
  images: GeneratedImage[];
  timestamp: number;
  config: GenerationConfig;
}

export interface ImageFilters {
  brightness: number;
  contrast: number;
  saturation: number;
  grayscale: number;
  sepia: number;
  blur: number;
}

export interface AppState {
  prompt: string;
  isGenerating: boolean;
  generatedImage: GeneratedImage | null;
  history: GeneratedImage[];
  error: string | null;
  config: GenerationConfig;
}

// --- Remix Types ---

export type RemixMode = 'text-to-image' | 'remix';

export interface RemixConfig {
  creativity: number; // 0.1 to 1.0
  structureMatch: boolean;
  characterMatch: boolean;
}

// --- Layer System Types ---

export type LayerType = 'base' | 'text' | 'image';

export interface BaseLayer {
  id: string;
  type: 'base';
  url: string; // The original generated image
  visible: boolean;
  filters: ImageFilters;
}

export interface TextLayer {
  id: string;
  type: 'text';
  text: string;
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number; // degrees
  fontSize: number;
  fontFamily: string;
  fontWeight: string;
  color: string; // Hex or rgba
  gradient?: {
    enabled: boolean;
    colors: string[]; // [startColor, endColor]
    direction: 'horizontal' | 'vertical';
  };
  visible: boolean;
}

export interface ImageLayer {
  id: string;
  type: 'image';
  url: string;
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number;
  visible: boolean;
  opacity: number;
}

export type Layer = BaseLayer | TextLayer | ImageLayer;

import React from 'react';
import { AspectRatio, ImageSize, GenerationConfig } from '../types';

interface SettingsPanelProps {
  config: GenerationConfig;
  onChange: (newConfig: GenerationConfig) => void;
  disabled: boolean;
}

export const SettingsPanel: React.FC<SettingsPanelProps> = ({ config, onChange, disabled }) => {

  const handleRatioChange = (ratio: AspectRatio) => {
    onChange({ ...config, aspectRatio: ratio });
  };

  const handleSizeChange = (size: ImageSize) => {
    onChange({ ...config, imageSize: size });
  };

  const handleBatchChange = (size: number) => {
    onChange({ ...config, batchSize: size });
  };

  return (
    <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 space-y-6">
      <div>
        <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-3">
          Aspect Ratio
        </label>
        <div className="grid grid-cols-3 gap-2">
          {Object.values(AspectRatio).map((ratio) => (
            <button
              key={ratio}
              onClick={() => handleRatioChange(ratio)}
              disabled={disabled}
              className={`
                px-3 py-2 text-sm rounded-lg border transition-all duration-200
                ${config.aspectRatio === ratio 
                  ? 'bg-indigo-600 border-indigo-500 text-white shadow-md shadow-indigo-900/20' 
                  : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600 hover:text-slate-200'}
                ${disabled ? 'opacity-50 cursor-not-allowed' : ''}
              `}
            >
              {ratio}
            </button>
          ))}
        </div>
      </div>

      <div>
        <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-3">
          Resolution (Pro)
        </label>
        <div className="flex space-x-2">
          {Object.values(ImageSize).map((size) => (
            <button
              key={size}
              onClick={() => handleSizeChange(size)}
              disabled={disabled}
              className={`
                flex-1 px-3 py-2 text-sm rounded-lg border transition-all duration-200
                ${config.imageSize === size 
                  ? 'bg-emerald-600 border-emerald-500 text-white shadow-md shadow-emerald-900/20' 
                  : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600 hover:text-slate-200'}
                ${disabled ? 'opacity-50 cursor-not-allowed' : ''}
              `}
            >
              {size}
            </button>
          ))}
        </div>
      </div>

      <div>
        <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-3">
          Batch Size (Simultaneous)
        </label>
        <div className="grid grid-cols-4 gap-2">
          {[1, 2, 4, 8].map((num) => (
            <button
              key={num}
              onClick={() => handleBatchChange(num)}
              disabled={disabled}
              className={`
                px-3 py-2 text-sm rounded-lg border transition-all duration-200
                ${config.batchSize === num 
                  ? 'bg-purple-600 border-purple-500 text-white shadow-md shadow-purple-900/20' 
                  : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600 hover:text-slate-200'}
                ${disabled ? 'opacity-50 cursor-not-allowed' : ''}
              `}
            >
              {num}
            </button>
          ))}
        </div>
        <p className="text-xs text-slate-500 mt-2">
          Generating more images simultaneously uses more resources.
        </p>
      </div>
    </div>
  );
};

import React from 'react';
import { GeneratedImage } from '../types';
import { Button } from './Button';

interface ImageDisplayProps {
  image: GeneratedImage | null;
  isGenerating: boolean;
  batchSize?: number;
  onEdit?: () => void;
}

export const ImageDisplay: React.FC<ImageDisplayProps> = ({ image, isGenerating, batchSize = 4, onEdit }) => {
  if (isGenerating && !image) {
    return (
      <div className="w-full aspect-square md:aspect-video rounded-xl bg-slate-800 border border-slate-700 flex flex-col items-center justify-center p-8 animate-pulse">
        <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-slate-300 font-medium">Creating {batchSize} variations...</p>
        <p className="text-slate-500 text-sm mt-2">Generating simultaneously for maximum creativity.</p>
      </div>
    );
  }

  if (!image && !isGenerating) {
    return (
      <div className="w-full aspect-square md:aspect-video rounded-xl bg-slate-800/30 border-2 border-dashed border-slate-700 flex flex-col items-center justify-center p-8 text-center">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 text-slate-600 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
        </svg>
        <p className="text-slate-400 text-lg">Your imagination awaits</p>
        <p className="text-slate-500 text-sm mt-1">Enter a prompt and click Generate</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="relative group rounded-xl overflow-hidden shadow-2xl shadow-black/50 border border-slate-700 bg-slate-900">
        <img 
          src={image?.url} 
          alt={image?.prompt}
          className="w-full h-auto object-contain max-h-[70vh] mx-auto"
        />
        {isGenerating && (
             <div className="absolute top-4 right-4 bg-black/60 backdrop-blur-md px-3 py-1 rounded-full border border-white/10 flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></div>
                <span className="text-[10px] font-bold text-white uppercase tracking-widest">Processing Batch...</span>
             </div>
        )}
        <div className="absolute inset-0 bg-gradient-to-t from-slate-900/90 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-end justify-between p-6">
            <div className="text-white">
                <p className="font-medium line-clamp-1 text-sm text-slate-300">{image?.prompt}</p>
                <p className="text-xs text-slate-500">{image?.config.imageSize} • {image?.config.aspectRatio}</p>
            </div>
          <div className="flex gap-2">
            {onEdit && (
              <Button 
                onClick={onEdit}
                variant="secondary"
                className="text-xs"
                icon={
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                  </svg>
                }
              >
                Edit
              </Button>
            )}
            <a 
                href={image?.url} 
                download={`nano-banana-${Date.now()}.png`}
                className="inline-flex items-center justify-center px-4 py-2 rounded-lg font-medium transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 bg-white text-slate-900 hover:bg-slate-200 text-xs"
            >
                Download
            </a>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AspectRatio, ImageSize, GenerationConfig, GeneratedImage, GenerationSession, RemixMode, RemixConfig } from './types';
import { checkApiKey, promptForApiKey, generateImageFromPrompt, describeImage, generateRemix } from './services/geminiService';
import { SettingsPanel } from './components/SettingsPanel';
import { ImageDisplay } from './components/ImageDisplay';
import { ImageEditor } from './components/ImageEditor';
import { Button } from './components/Button';
import { HistorySidebar } from './components/HistorySidebar';

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState<boolean>(false);

  // Tab State
  const [activeTab, setActiveTab] = useState<RemixMode>('text-to-image');

  // Generation State
  const [prompt, setPrompt] = useState<string>('');
  const [isGenerating, setIsGenerating] = useState<boolean>(false);

  // Remix State
  const [remixImage, setRemixImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [remixConfig, setRemixConfig] = useState<RemixConfig>({
      creativity: 0.2,
      structureMatch: true,
      characterMatch: false
  });

  // Batch State
  const [generatedBatch, setGeneratedBatch] = useState<GeneratedImage[]>([]);
  const [selectedImageId, setSelectedImageId] = useState<string | null>(null);

  const [config, setConfig] = useState<GenerationConfig>({
    aspectRatio: AspectRatio.Square,
    imageSize: ImageSize.OneK,
    batchSize: 4 // Default to 4
  });

  // Editor State
  const [isEditing, setIsEditing] = useState<boolean>(false);

  // History State
  const [history, setHistory] = useState<GenerationSession[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState<boolean>(false);

  const [error, setError] = useState<string | null>(null);

  // Check for API key on mount
  useEffect(() => {
    const initAuth = async () => {
      try {
        const hasKey = await checkApiKey();
        setApiKeyReady(hasKey);
      } catch (e) {
        console.error("Failed to check API key status", e);
      }
    };
    initAuth();
  }, []);

  // Draft Saving (LocalStorage)
  useEffect(() => {
    const savedPrompt = localStorage.getItem('draft_prompt');
    if (savedPrompt) {
        setPrompt(savedPrompt);
    }

    // Load History
    try {
        const savedHistory = localStorage.getItem('app_history');
        if (savedHistory) {
            setHistory(JSON.parse(savedHistory));
        }
    } catch (e) {
        console.error("Failed to load history", e);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('draft_prompt', prompt);
  }, [prompt]);

  useEffect(() => {
    try {
        localStorage.setItem('app_history', JSON.stringify(history));
    } catch (e) {
        console.error("Storage limit reached or error saving history", e);
        if (history.length > 10) {
            const trimmed = history.slice(0, 10);
            setHistory(trimmed);
            try { localStorage.setItem('app_history', JSON.stringify(trimmed)); } catch(err){}
        }
    }
  }, [history]);

  const handleConnectKey = async () => {
    try {
      await promptForApiKey();
      setApiKeyReady(true);
      setError(null);
    } catch (e) {
      console.error(e);
      setError("Failed to connect API Key.");
    }
  };

  const selectedImage = generatedBatch.find(img => img.id === selectedImageId) || null;

  const addToHistory = (batch: GeneratedImage[]) => {
      const newSession: GenerationSession = {
          id: Date.now().toString(),
          prompt: prompt,
          images: batch,
          timestamp: Date.now(),
          config: { ...config }
      };
      setHistory(prev => [newSession, ...prev]);
  };

  const handleSelectSession = (session: GenerationSession) => {
      setPrompt(session.prompt);
      setConfig(session.config);
      setGeneratedBatch(session.images);
      if (session.images.length > 0) {
          setSelectedImageId(session.images[0].id);
      }
      setIsEditing(false);
  };

  const handleClearHistory = () => {
      if (confirm("Are you sure you want to clear all history? This cannot be undone.")) {
          setHistory([]);
          localStorage.removeItem('app_history');
      }
  };

  const handleRemixUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = async (event) => {
          const result = event.target?.result as string;
          setRemixImage(result);
          setIsAnalyzing(true);
          try {
             const description = await describeImage(result);
             setPrompt(description);
          } catch (err) {
              console.error(err);
              setError("Could not analyze image semantics.");
          } finally {
              setIsAnalyzing(false);
          }
      };
      reader.readAsDataURL(file);
  };

  const handleGenerate = async () => {
    if (!prompt.trim()) {
      setError("Please enter a description for the image.");
      return;
    }

    if (activeTab === 'remix' && !remixImage) {
        setError("Please upload a reference image for remixing.");
        return;
    }

    if (!apiKeyReady) {
        await handleConnectKey();
        return;
    }

    setIsGenerating(true);
    setIsEditing(false);
    setError(null);
    setGeneratedBatch([]); 
    setSelectedImageId(null);

    const successfulImages: GeneratedImage[] = [];
    const batchSize = config.batchSize;

    try {
      // Logic for simultaneous progressive generation
      const promises = Array(batchSize).fill(null).map(async (_, index) => {
        try {
          let imageUrl = "";
          if (activeTab === 'remix' && remixImage) {
              imageUrl = await generateRemix(remixImage, prompt, remixConfig, config);
          } else {
              imageUrl = await generateImageFromPrompt(prompt, config);
          }

          const newImg: GeneratedImage = {
            id: `${Date.now()}-${index}`,
            url: imageUrl,
            prompt: prompt,
            config: { ...config },
            timestamp: Date.now()
          };

          // Progressive update: add image to batch as soon as it's ready
          setGeneratedBatch(prev => {
              const updated = [...prev, newImg];
              // Automatically select the first image that arrives
              if (updated.length === 1) setSelectedImageId(newImg.id);
              return updated;
          });

          successfulImages.push(newImg);
        } catch (e: any) {
          console.error(`Generation variation ${index} failed:`, e);
          // If this was the last possible attempt and all failed, we'll catch it later
        }
      });

      await Promise.allSettled(promises);

      if (successfulImages.length === 0) {
        throw new Error("Failed to generate any images in this batch. Please check your API key and try again.");
      }

      addToHistory(successfulImages);

    } catch (err: any) {
      console.error(err);
      if (err.message && err.message.includes("API Key Error")) {
        setApiKeyReady(false);
        setError("API Key access lost or invalid. Please reconnect.");
      } else {
        setError(err.message || "Something went wrong while generating the images.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSaveEditedImage = (newUrl: string) => {
    if (selectedImageId) {
      const updatedBatch = generatedBatch.map(img => 
        img.id === selectedImageId 
          ? { ...img, url: newUrl } 
          : img
      );
      setGeneratedBatch(updatedBatch);
      setIsEditing(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 pb-12 font-sans overflow-x-hidden">
      <header className="border-b border-slate-800 bg-[#0f172a]/95 sticky top-0 z-30 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <span className="text-white font-bold text-lg">N</span>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">
              Nano Banana Pro
            </h1>
          </div>

          <div className="hidden md:flex space-x-1 bg-slate-800/50 p-1 rounded-lg border border-slate-700">
             <button 
                onClick={() => setActiveTab('text-to-image')}
                className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'text-to-image' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
             >
                Text to Image
             </button>
             <button 
                onClick={() => setActiveTab('remix')}
                className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'remix' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
             >
                Image Remix
             </button>
          </div>

          <div className="flex items-center gap-3">
            {!apiKeyReady ? (
              <Button onClick={handleConnectKey} variant="secondary" className="text-xs">
                Connect API Key
              </Button>
            ) : (
              <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-xs font-medium text-emerald-500 hidden sm:inline">System Ready</span>
              </div>
            )}

            <button 
              onClick={() => setIsHistoryOpen(true)}
              className="p-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-300 transition relative"
              title="History"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              {history.length > 0 && (
                <span className="absolute top-1 right-1 w-2 h-2 bg-indigo-500 rounded-full"></span>
              )}
            </button>
          </div>
        </div>
      </header>

      <HistorySidebar 
        isOpen={isHistoryOpen} 
        onClose={() => setIsHistoryOpen(false)} 
        history={history}
        onSelectSession={handleSelectSession}
        onClearHistory={handleClearHistory}
      />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {error && (
          <div className="mb-6 p-4 rounded-lg bg-red-900/20 border border-red-900/50 flex items-start gap-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-red-400 mt-0.5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
            </svg>
            <div className="flex-1 text-sm text-red-200">{error}</div>
            <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
              </svg>
            </button>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 animate-fade-in">
        <div className="lg:col-span-4 space-y-6 order-2 lg:order-1">

            {activeTab === 'remix' && (
                <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl space-y-4">
                    <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-wider">1. Reference Image</h3>
                    <div className="relative border-2 border-dashed border-slate-600 rounded-lg p-6 flex flex-col items-center justify-center bg-slate-900/50 hover:bg-slate-900 transition group">
                        {remixImage ? (
                            <div className="relative w-full aspect-video">
                                <img src={remixImage} alt="Reference" className="w-full h-full object-contain rounded-md" />
                                <button 
                                    onClick={(e) => { e.preventDefault(); setRemixImage(null); }} 
                                    className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white rounded-full p-1 transition"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                                        <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                                    </svg>
                                </button>
                                {isAnalyzing && (
                                    <div className="absolute inset-0 flex items-center justify-center bg-black/50 backdrop-blur-sm rounded-md">
                                        <div className="text-center">
                                            <div className="w-6 h-6 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin mx-auto mb-2"></div>
                                            <span className="text-xs text-indigo-200">Analyzing Semantics...</span>
                                        </div>
                                    </div>
                                )}
                            </div>
                        ) : (
                            <>
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-slate-500 mb-2 group-hover:text-indigo-400 transition" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                                </svg>
                                <p className="text-sm text-slate-400">Click to upload reference</p>
                                <input type="file" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept="image/*" onChange={handleRemixUpload} />
                            </>
                        )}
                    </div>

                    <div className="space-y-4 pt-4 border-t border-slate-700">
                        <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-wider">2. Similarity Settings</h3>

                        <div>
                            <div className="flex justify-between text-xs mb-1">
                                <span className="text-slate-400">Variation Level</span>
                                <span className="text-indigo-400 font-mono">{Math.round(remixConfig.creativity * 100)}%</span>
                            </div>
                            <input 
                                type="range" 
                                min="0.1" max="1.0" step="0.1" 
                                value={remixConfig.creativity}
                                onChange={(e) => setRemixConfig({...remixConfig, creativity: Number(e.target.value)})}
                                className="w-full accent-indigo-500 h-1.5 bg-slate-700 rounded-lg cursor-pointer"
                            />
                            <div className="flex justify-between text-[10px] text-slate-500 mt-1">
                                <span>High Fidelity</span>
                                <span>Reimagine</span>
                            </div>
                        </div>

                        <div className="space-y-2">
                             <label className="flex items-center space-x-2 text-sm text-slate-300 cursor-pointer p-2 rounded hover:bg-slate-800 transition">
                                <input 
                                    type="checkbox" 
                                    checked={remixConfig.structureMatch}
                                    onChange={(e) => setRemixConfig({...remixConfig, structureMatch: e.target.checked})}
                                    className="form-checkbox h-4 w-4 text-indigo-600 rounded border-slate-600 bg-slate-700 focus:ring-indigo-500"
                                />
                                <div>
                                    <span className="block font-medium">Structure Lock</span>
                                    <span className="block text-[10px] text-slate-500">Strictly preserve layout & geometry</span>
                                </div>
                             </label>
                             <label className="flex items-center space-x-2 text-sm text-slate-300 cursor-pointer p-2 rounded hover:bg-slate-800 transition">
                                <input 
                                    type="checkbox" 
                                    checked={remixConfig.characterMatch}
                                    onChange={(e) => setRemixConfig({...remixConfig, characterMatch: e.target.checked})}
                                    className="form-checkbox h-4 w-4 text-indigo-600 rounded border-slate-600 bg-slate-700 focus:ring-indigo-500"
                                />
                                <div>
                                    <span className="block font-medium">Character Consistency</span>
                                    <span className="block text-[10px] text-slate-500">Keep facial features similar</span>
                                </div>
                             </label>
                        </div>
                    </div>
                </div>
            )}

            <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl">
            <div className="flex items-center justify-between mb-2">
                <label htmlFor="prompt" className="block text-sm font-semibold text-indigo-400">
                    {activeTab === 'remix' ? '3. Description (Auto-Analyzed)' : 'Prompt'}
                </label>
            </div>
            <textarea
                id="prompt"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder={activeTab === 'remix' 
                    ? "The AI will analyze the image and fill this description." 
                    : "Describe your imagination..."}
                className="w-full h-40 bg-slate-900/80 border border-slate-700 rounded-lg p-3 text-slate-200 placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all resize-none text-sm leading-relaxed"
                disabled={isGenerating || isEditing}
            />

            <div className="mt-4">
                <Button 
                onClick={handleGenerate} 
                isLoading={isGenerating} 
                disabled={isEditing || (activeTab === 'remix' && !remixImage)}
                className="w-full h-12 text-lg shadow-indigo-500/20"
                variant={activeTab === 'remix' ? 'secondary' : 'primary'}
                >
                {isGenerating ? `Generating ${config.batchSize} Images...` : `Generate ${config.batchSize} Variations`}
                </Button>
            </div>
            </div>

            <SettingsPanel 
            config={config} 
            onChange={setConfig} 
            disabled={isGenerating || isEditing} 
            />
        </div>

        <div className="lg:col-span-8 order-1 lg:order-2 space-y-6">
            {isEditing && selectedImage ? (
                <ImageEditor 
                imageUrl={selectedImage.url} 
                onSave={handleSaveEditedImage} 
                onCancel={() => setIsEditing(false)} 
                />
            ) : (
                <>
                <ImageDisplay 
                    image={selectedImage} 
                    isGenerating={isGenerating} 
                    batchSize={config.batchSize}
                    onEdit={selectedImage ? () => setIsEditing(true) : undefined}
                />

                {(generatedBatch.length > 0 || isGenerating) && (
                    <div className="bg-slate-800/50 rounded-xl p-4 border border-slate-700">
                        <div className="flex justify-between items-center mb-3">
                            <h3 className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Variations</h3>
                            {isGenerating && (
                                <span className="text-[10px] text-indigo-400 animate-pulse font-mono">
                                    {generatedBatch.length} / {config.batchSize} READY
                                </span>
                            )}
                        </div>
                        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                            {/* Render actual results */}
                            {generatedBatch.map((img) => (
                                <button
                                    key={img.id}
                                    onClick={() => setSelectedImageId(img.id)}
                                    className={`
                                        relative aspect-square rounded-lg overflow-hidden border-2 transition-all duration-200
                                        ${selectedImageId === img.id 
                                            ? 'border-indigo-500 ring-2 ring-indigo-500/30' 
                                            : 'border-slate-700 hover:border-slate-500 opacity-70 hover:opacity-100'}
                                    `}
                                >
                                    <img 
                                        src={img.url} 
                                        alt="Variation" 
                                        className="w-full h-full object-cover"
                                    />
                                    {selectedImageId === img.id && (
                                        <div className="absolute inset-0 bg-indigo-500/10 pointer-events-none"></div>
                                    )}
                                </button>
                            ))}

                            {/* Render placeholders for images still generating */}
                            {isGenerating && Array(config.batchSize - generatedBatch.length).fill(null).map((_, i) => (
                                <div key={`skeleton-${i}`} className="aspect-square rounded-lg bg-slate-800/50 border-2 border-slate-700/50 border-dashed flex items-center justify-center animate-pulse">
                                    <div className="w-6 h-6 border-2 border-slate-600 border-t-transparent rounded-full animate-spin"></div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
                </>
            )}
        </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { AspectRatio, ImageSize, GenerationConfig, GeneratedImage, GenerationSession, RemixMode, RemixConfig } from './types';
import { checkApiKey, promptForApiKey, generateImageFromPrompt, describeImage, generateRemix } from './services/geminiService';
import { SettingsPanel } from './components/SettingsPanel';
import { ImageDisplay } from './components/ImageDisplay';
import { ImageEditor } from './components/ImageEditor';
import { Button } from './components/Button';
import { HistorySidebar } from './components/HistorySidebar';

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState<boolean>(false);

  // Tab State
  const [activeTab, setActiveTab] = useState<RemixMode>('text-to-image');

  // Generation State
  const [prompt, setPrompt] = useState<string>('');
  const [isBulkMode, setIsBulkMode] = useState<boolean>(false);
  const [isGenerating, setIsGenerating] = useState<boolean>(false);

  // Remix State
  const [remixImage, setRemixImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [remixConfig, setRemixConfig] = useState<RemixConfig>({
      creativity: 0.2,
      structureMatch: true,
      characterMatch: false
  });

  // Batch State
  const [generatedBatch, setGeneratedBatch] = useState<GeneratedImage[]>([]);
  const [selectedImageId, setSelectedImageId] = useState<string | null>(null);

  const [config, setConfig] = useState<GenerationConfig>({
    aspectRatio: AspectRatio.Square,
    imageSize: ImageSize.OneK,
    batchSize: 4 
  });

  // Editor State
  const [isEditing, setIsEditing] = useState<boolean>(false);

  // History State
  const [history, setHistory] = useState<GenerationSession[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState<boolean>(false);

  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const hasKey = await checkApiKey();
        setApiKeyReady(hasKey);
      } catch (e) {
        console.error("Failed to check API key status", e);
      }
    };
    initAuth();
  }, []);

  useEffect(() => {
    const savedPrompt = localStorage.getItem('draft_prompt');
    if (savedPrompt) setPrompt(savedPrompt);

    try {
        const savedHistory = localStorage.getItem('app_history');
        if (savedHistory) setHistory(JSON.parse(savedHistory));
    } catch (e) {
        console.error("Failed to load history", e);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('draft_prompt', prompt);
  }, [prompt]);

  useEffect(() => {
    try {
        localStorage.setItem('app_history', JSON.stringify(history));
    } catch (e) {
        if (history.length > 10) {
            const trimmed = history.slice(0, 10);
            setHistory(trimmed);
        }
    }
  }, [history]);

  const handleConnectKey = async () => {
    try {
      await promptForApiKey();
      setApiKeyReady(true);
      setError(null);
    } catch (e) {
      setError("Failed to connect API Key.");
    }
  };

  const selectedImage = generatedBatch.find(img => img.id === selectedImageId) || null;

  const addToHistory = (batch: GeneratedImage[]) => {
      const newSession: GenerationSession = {
          id: Date.now().toString(),
          prompt: isBulkMode ? `${batch.length} multiple prompts` : prompt,
          images: batch,
          timestamp: Date.now(),
          config: { ...config }
      };
      setHistory(prev => [newSession, ...prev]);
  };

  const handleSelectSession = (session: GenerationSession) => {
      setPrompt(session.prompt);
      setConfig(session.config);
      setGeneratedBatch(session.images);
      if (session.images.length > 0) setSelectedImageId(session.images[0].id);
      setIsEditing(false);
  };

  const handleClearHistory = () => {
      if (confirm("Are you sure?")) {
          setHistory([]);
          localStorage.removeItem('app_history');
      }
  };

  const handleRemixUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = async (event) => {
          const result = event.target?.result as string;
          setRemixImage(result);
          setIsAnalyzing(true);
          try {
             const description = await describeImage(result);
             setPrompt(description);
          } catch (err) {
              setError("Could not analyze image.");
          } finally {
              setIsAnalyzing(false);
          }
      };
      reader.readAsDataURL(file);
  };

  const handleGenerate = async () => {
    if (!prompt.trim()) {
      setError("Please enter at least one prompt.");
      return;
    }

    if (!apiKeyReady) {
        await handleConnectKey();
        return;
    }

    // Determine tasks
    let promptTasks: string[] = [];
    if (isBulkMode && activeTab === 'text-to-image') {
        promptTasks = prompt.split('\n').map(p => p.trim()).filter(p => p.length > 0);
    } else {
        // If not bulk mode, we generate 'batchSize' images for the single prompt
        promptTasks = Array(config.batchSize).fill(prompt);
    }

    if (promptTasks.length === 0) return;

    setIsGenerating(true);
    setIsEditing(false);
    setError(null);
    setGeneratedBatch([]); 
    setSelectedImageId(null);

    const successfulImages: GeneratedImage[] = [];

    try {
      const promises = promptTasks.map(async (taskPrompt, index) => {
        try {
          let imageUrl = "";
          if (activeTab === 'remix' && remixImage) {
              imageUrl = await generateRemix(remixImage, taskPrompt, remixConfig, config);
          } else {
              imageUrl = await generateImageFromPrompt(taskPrompt, config);
          }

          const newImg: GeneratedImage = {
            id: `${Date.now()}-${index}`,
            url: imageUrl,
            prompt: taskPrompt,
            config: { ...config },
            timestamp: Date.now()
          };

          setGeneratedBatch(prev => {
              const updated = [...prev, newImg];
              if (updated.length === 1) setSelectedImageId(newImg.id);
              return updated;
          });

          successfulImages.push(newImg);
        } catch (e) {
          console.error(`Prompt "${taskPrompt}" failed:`, e);
        }
      });

      await Promise.allSettled(promises);

      if (successfulImages.length === 0) {
        throw new Error("Failed to generate any images. Check your connection or API key.");
      }

      addToHistory(successfulImages);

    } catch (err: any) {
      setError(err.message || "Something went wrong.");
    } finally {
      setIsGenerating(false);
    }
  };

  const promptsCount = prompt.split('\n').filter(p => p.trim().length > 0).length;

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 pb-12 font-sans overflow-x-hidden">
      <header className="border-b border-slate-800 bg-[#0f172a]/95 sticky top-0 z-30 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <span className="text-white font-bold text-lg">N</span>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">
              Nano Banana Pro
            </h1>
          </div>

          <div className="hidden md:flex space-x-1 bg-slate-800/50 p-1 rounded-lg border border-slate-700">
             <button onClick={() => setActiveTab('text-to-image')} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'text-to-image' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Text to Image
             </button>
             <button onClick={() => setActiveTab('remix')} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'remix' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Image Remix
             </button>
          </div>

          <div className="flex items-center gap-3">
            {!apiKeyReady ? (
              <Button onClick={handleConnectKey} variant="secondary" className="text-xs">Connect API Key</Button>
            ) : (
              <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-xs font-medium text-emerald-500 hidden sm:inline">System Ready</span>
              </div>
            )}
            <button onClick={() => setIsHistoryOpen(true)} className="p-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-300 transition relative">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      <HistorySidebar 
        isOpen={isHistoryOpen} 
        onClose={() => setIsHistoryOpen(false)} 
        history={history}
        onSelectSession={handleSelectSession}
        onClearHistory={handleClearHistory}
      />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {error && (
          <div className="mb-6 p-4 rounded-lg bg-red-900/20 border border-red-900/50 flex items-start gap-3">
            <div className="flex-1 text-sm text-red-200">{error}</div>
            <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">×</button>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 animate-fade-in">
          <div className="lg:col-span-4 space-y-6 order-2 lg:order-1">

            {activeTab === 'remix' && (
                <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl space-y-4">
                    <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-wider">1. Reference Image</h3>
                    <div className="relative border-2 border-dashed border-slate-600 rounded-lg p-6 flex flex-col items-center justify-center bg-slate-900/50 hover:bg-slate-900 transition group">
                        {remixImage ? (
                            <div className="relative w-full aspect-video">
                                <img src={remixImage} alt="Reference" className="w-full h-full object-contain rounded-md" />
                                <button onClick={(e) => { e.preventDefault(); setRemixImage(null); }} className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white rounded-full p-1 transition">×</button>
                                {isAnalyzing && (
                                    <div className="absolute inset-0 flex items-center justify-center bg-black/50 backdrop-blur-sm rounded-md">
                                        <div className="w-6 h-6 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                                    </div>
                                )}
                            </div>
                        ) : (
                            <>
                                <p className="text-sm text-slate-400">Click to upload reference</p>
                                <input type="file" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept="image/*" onChange={handleRemixUpload} />
                            </>
                        )}
                    </div>
                </div>
            )}

            <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl">
              <div className="flex items-center justify-between mb-2">
                  <label htmlFor="prompt" className="block text-sm font-semibold text-indigo-400">
                      {activeTab === 'remix' ? '3. Description' : 'Prompts'}
                  </label>
                  {activeTab === 'text-to-image' && (
                    <button 
                      onClick={() => setIsBulkMode(!isBulkMode)}
                      className={`text-[10px] px-2 py-0.5 rounded border transition-colors ${isBulkMode ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-700 border-slate-600 text-slate-400'}`}
                    >
                      {isBulkMode ? 'Bulk Mode: ON' : 'Bulk Mode: OFF'}
                    </button>
                  )}
              </div>
              <div className="relative">
                <textarea
                    id="prompt"
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder={isBulkMode ? "Enter each prompt on a new line..." : "Describe your imagination..."}
                    className={`w-full h-48 bg-slate-900/80 border border-slate-700 rounded-lg p-3 text-slate-200 placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all resize-none text-sm leading-relaxed ${isBulkMode ? 'font-mono' : ''}`}
                    disabled={isGenerating || isEditing}
                />
                {isBulkMode && promptsCount > 0 && (
                  <div className="absolute bottom-3 right-3 bg-indigo-600/20 text-indigo-400 text-[10px] font-bold px-2 py-0.5 rounded border border-indigo-500/30">
                    {promptsCount} PROMPTS DETECTED
                  </div>
                )}
              </div>

              <div className="mt-4">
                  <Button 
                    onClick={handleGenerate} 
                    isLoading={isGenerating} 
                    disabled={isEditing || (activeTab === 'remix' && !remixImage)}
                    className="w-full h-12 text-lg shadow-indigo-500/20"
                  >
                    {isGenerating 
                      ? `Generating ${isBulkMode ? promptsCount : config.batchSize} Images...` 
                      : isBulkMode ? `Generate ${promptsCount} Bulk Images` : `Generate ${config.batchSize} Variations`}
                  </Button>
              </div>
            </div>

            <SettingsPanel config={config} onChange={setConfig} disabled={isGenerating || isEditing || isBulkMode} />
          </div>

          <div className="lg:col-span-8 order-1 lg:order-2 space-y-6">
              {isEditing && selectedImage ? (
                  <ImageEditor imageUrl={selectedImage.url} onSave={(url) => {
                      setGeneratedBatch(prev => prev.map(img => img.id === selectedImageId ? {...img, url} : img));
                      setIsEditing(false);
                  }} onCancel={() => setIsEditing(false)} />
              ) : (
                  <>
                  <ImageDisplay 
                      image={selectedImage} 
                      isGenerating={isGenerating} 
                      batchSize={isBulkMode ? promptsCount : config.batchSize}
                      onEdit={selectedImage ? () => setIsEditing(true) : undefined}
                  />

                  {(generatedBatch.length > 0 || isGenerating) && (
                      <div className="bg-slate-800/50 rounded-xl p-4 border border-slate-700">
                          <h3 className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-3">Results</h3>
                          <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-6 gap-3">
                              {generatedBatch.map((img) => (
                                  <button
                                      key={img.id}
                                      onClick={() => setSelectedImageId(img.id)}
                                      className={`relative aspect-square rounded-lg overflow-hidden border-2 transition-all ${selectedImageId === img.id ? 'border-indigo-500 ring-2 ring-indigo-500/30' : 'border-slate-700 hover:border-slate-500'}`}
                                  >
                                      <img src={img.url} alt="Result" className="w-full h-full object-cover" />
                                      {isBulkMode && (
                                        <div className="absolute top-1 left-1 bg-black/60 text-[8px] px-1 rounded text-white truncate max-w-[80%]">
                                          {img.prompt}
                                        </div>
                                      )}
                                  </button>
                              ))}
                              {isGenerating && Array(Math.max(0, (isBulkMode ? promptsCount : config.batchSize) - generatedBatch.length)).fill(null).map((_, i) => (
                                  <div key={i} className="aspect-square rounded-lg bg-slate-800/50 border-2 border-slate-700/50 border-dashed flex items-center justify-center animate-pulse">
                                      <div className="w-4 h-4 border-2 border-slate-600 border-t-transparent rounded-full animate-spin"></div>
                                  </div>
                              ))}
                          </div>
                      </div>
                  )}
                  </>
              )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { AspectRatio, ImageSize, GenerationConfig, GeneratedImage, GenerationSession, RemixMode, RemixConfig } from './types';
import { checkApiKey, promptForApiKey, generateImageFromPrompt, describeImage, generateRemix } from './services/geminiService';
import { SettingsPanel } from './components/SettingsPanel';
import { ImageDisplay } from './components/ImageDisplay';
import { ImageEditor } from './components/ImageEditor';
import { Button } from './components/Button';
import { HistorySidebar } from './components/HistorySidebar';

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState<boolean>(false);

  // Tab State
  const [activeTab, setActiveTab] = useState<RemixMode>('text-to-image');

  // Generation State
  const [prompt, setPrompt] = useState<string>('');
  const [isBulkMode, setIsBulkMode] = useState<boolean>(false);
  const [isGenerating, setIsGenerating] = useState<boolean>(false);

  // Remix State
  const [remixImage, setRemixImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [remixConfig, setRemixConfig] = useState<RemixConfig>({
      creativity: 0.2,
      structureMatch: true,
      characterMatch: false
  });

  // Batch State
  const [generatedBatch, setGeneratedBatch] = useState<GeneratedImage[]>([]);
  const [selectedImageId, setSelectedImageId] = useState<string | null>(null);

  const [config, setConfig] = useState<GenerationConfig>({
    aspectRatio: AspectRatio.Square,
    imageSize: ImageSize.OneK,
    batchSize: 4 
  });

  // Editor State
  const [isEditing, setIsEditing] = useState<boolean>(false);

  // History State
  const [history, setHistory] = useState<GenerationSession[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState<boolean>(false);

  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const hasKey = await checkApiKey();
        setApiKeyReady(hasKey);
      } catch (e) {
        console.error("Failed to check API key status", e);
      }
    };
    initAuth();
  }, []);

  useEffect(() => {
    const savedPrompt = localStorage.getItem('draft_prompt');
    if (savedPrompt) setPrompt(savedPrompt);

    try {
        const savedHistory = localStorage.getItem('app_history');
        if (savedHistory) setHistory(JSON.parse(savedHistory));
    } catch (e) {
        console.error("Failed to load history", e);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('draft_prompt', prompt);
  }, [prompt]);

  useEffect(() => {
    try {
        localStorage.setItem('app_history', JSON.stringify(history));
    } catch (e) {
        if (history.length > 10) {
            const trimmed = history.slice(0, 10);
            setHistory(trimmed);
        }
    }
  }, [history]);

  const handleConnectKey = async () => {
    try {
      await promptForApiKey();
      setApiKeyReady(true);
      setError(null);
    } catch (e) {
      setError("Failed to connect API Key.");
    }
  };

  const selectedImage = generatedBatch.find(img => img.id === selectedImageId) || null;

  const addToHistory = (batch: GeneratedImage[]) => {
      const newSession: GenerationSession = {
          id: Date.now().toString(),
          prompt: isBulkMode ? `${batch.length} multiple prompts` : prompt,
          images: batch,
          timestamp: Date.now(),
          config: { ...config }
      };
      setHistory(prev => [newSession, ...prev]);
  };

  const handleSelectSession = (session: GenerationSession) => {
      setPrompt(session.prompt);
      setConfig(session.config);
      setGeneratedBatch(session.images);
      if (session.images.length > 0) setSelectedImageId(session.images[0].id);
      setIsEditing(false);
  };

  const handleClearHistory = () => {
      if (confirm("Are you sure?")) {
          setHistory([]);
          localStorage.removeItem('app_history');
      }
  };

  const handleRemixUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = async (event) => {
          const result = event.target?.result as string;
          setRemixImage(result);
          setIsAnalyzing(true);
          try {
             const description = await describeImage(result);
             setPrompt(description);
          } catch (err) {
              setError("Could not analyze image.");
          } finally {
              setIsAnalyzing(false);
          }
      };
      reader.readAsDataURL(file);
  };

  const handleGenerate = async () => {
    if (!prompt.trim()) {
      setError("Please enter at least one prompt.");
      return;
    }

    if (!apiKeyReady) {
        await handleConnectKey();
        return;
    }

    // Determine tasks
    let promptTasks: string[] = [];
    if (isBulkMode && activeTab === 'text-to-image') {
        promptTasks = prompt.split('\n').map(p => p.trim()).filter(p => p.length > 0);
    } else {
        // If not bulk mode, we generate 'batchSize' images for the single prompt
        promptTasks = Array(config.batchSize).fill(prompt);
    }

    if (promptTasks.length === 0) return;

    setIsGenerating(true);
    setIsEditing(false);
    setError(null);
    setGeneratedBatch([]); 
    setSelectedImageId(null);

    const successfulImages: GeneratedImage[] = [];

    try {
      const promises = promptTasks.map(async (taskPrompt, index) => {
        try {
          let imageUrl = "";
          if (activeTab === 'remix' && remixImage) {
              imageUrl = await generateRemix(remixImage, taskPrompt, remixConfig, config);
          } else {
              imageUrl = await generateImageFromPrompt(taskPrompt, config);
          }

          const newImg: GeneratedImage = {
            id: `${Date.now()}-${index}`,
            url: imageUrl,
            prompt: taskPrompt,
            config: { ...config },
            timestamp: Date.now()
          };

          setGeneratedBatch(prev => {
              const updated = [...prev, newImg];
              if (updated.length === 1) setSelectedImageId(newImg.id);
              return updated;
          });

          successfulImages.push(newImg);
        } catch (e) {
          console.error(`Prompt "${taskPrompt}" failed:`, e);
        }
      });

      await Promise.allSettled(promises);

      if (successfulImages.length === 0) {
        throw new Error("Failed to generate any images. Check your connection or API key.");
      }

      addToHistory(successfulImages);

    } catch (err: any) {
      setError(err.message || "Something went wrong.");
    } finally {
      setIsGenerating(false);
    }
  };

  const promptsCount = prompt.split('\n').filter(p => p.trim().length > 0).length;

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 pb-12 font-sans overflow-x-hidden">
      <header className="border-b border-slate-800 bg-[#0f172a]/95 sticky top-0 z-30 backdrop-blur-md">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <span className="text-white font-bold text-lg">N</span>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">
              Nano Banana Pro
            </h1>
          </div>

          <div className="hidden md:flex space-x-1 bg-slate-800/50 p-1 rounded-lg border border-slate-700">
             <button onClick={() => setActiveTab('text-to-image')} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'text-to-image' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Text to Image
             </button>
             <button onClick={() => setActiveTab('remix')} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'remix' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Image Remix
             </button>
          </div>

          <div className="flex items-center gap-3">
            {!apiKeyReady ? (
              <Button onClick={handleConnectKey} variant="secondary" className="text-xs">Connect API Key</Button>
            ) : (
              <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-xs font-medium text-emerald-500 hidden sm:inline">System Ready</span>
              </div>
            )}
            <button onClick={() => setIsHistoryOpen(true)} className="p-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-300 transition relative">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      <HistorySidebar 
        isOpen={isHistoryOpen} 
        onClose={() => setIsHistoryOpen(false)} 
        history={history}
        onSelectSession={handleSelectSession}
        onClearHistory={handleClearHistory}
      />

      {/* Main Single Column Layout */}
      <main className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8 py-8 animate-fade-in">

        {error && (
          <div className="mb-6 p-4 rounded-lg bg-red-900/20 border border-red-900/50 flex items-start gap-3">
            <div className="flex-1 text-sm text-red-200">{error}</div>
            <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">×</button>
          </div>
        )}

        {isEditing && selectedImage ? (
            <div className="space-y-4">
                <div className="flex justify-between items-center mb-2">
                    <h2 className="text-lg font-semibold text-white">Editor Studio</h2>
                    <Button variant="ghost" onClick={() => setIsEditing(false)} className="text-xs">
                        Back to Results
                    </Button>
                </div>
                <ImageEditor 
                    imageUrl={selectedImage.url} 
                    onSave={(url) => {
                        setGeneratedBatch(prev => prev.map(img => img.id === selectedImageId ? {...img, url} : img));
                        setIsEditing(false);
                    }} 
                    onCancel={() => setIsEditing(false)} 
                />
            </div>
        ) : (
            <div className="space-y-8">
                {/* SECTION 1: INPUTS */}
                <div className="space-y-6">
                    {/* Remix Reference Upload */}
                    {activeTab === 'remix' && (
                        <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl space-y-4">
                            <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-wider">Reference Image</h3>
                            <div className="relative border-2 border-dashed border-slate-600 rounded-lg p-6 flex flex-col items-center justify-center bg-slate-900/50 hover:bg-slate-900 transition group">
                                {remixImage ? (
                                    <div className="relative w-full aspect-video max-h-[300px]">
                                        <img src={remixImage} alt="Reference" className="w-full h-full object-contain rounded-md" />
                                        <button onClick={(e) => { e.preventDefault(); setRemixImage(null); }} className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white rounded-full p-1 transition">×</button>
                                        {isAnalyzing && (
                                            <div className="absolute inset-0 flex items-center justify-center bg-black/50 backdrop-blur-sm rounded-md">
                                                <div className="w-6 h-6 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                                            </div>
                                        )}
                                    </div>
                                ) : (
                                    <>
                                        <p className="text-sm text-slate-400">Click to upload reference</p>
                                        <input type="file" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept="image/*" onChange={handleRemixUpload} />
                                    </>
                                )}
                            </div>
                        </div>
                    )}

                    {/* Prompt Input Area */}
                    <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl">
                        <div className="flex items-center justify-between mb-2">
                            <label htmlFor="prompt" className="block text-sm font-semibold text-indigo-400">
                                {activeTab === 'remix' ? 'Description & Modifiers' : 'Creative Prompt'}
                            </label>
                            {activeTab === 'text-to-image' && (
                                <button 
                                onClick={() => setIsBulkMode(!isBulkMode)}
                                className={`text-[10px] px-2 py-0.5 rounded border transition-colors ${isBulkMode ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-700 border-slate-600 text-slate-400'}`}
                                >
                                {isBulkMode ? 'Bulk Mode: ON' : 'Bulk Mode: OFF'}
                                </button>
                            )}
                        </div>
                        <div className="relative">
                            <textarea
                                id="prompt"
                                value={prompt}
                                onChange={(e) => setPrompt(e.target.value)}
                                placeholder={isBulkMode ? "Enter each prompt on a new line..." : "Describe your imagination..."}
                                className={`w-full h-32 bg-slate-900/80 border border-slate-700 rounded-lg p-3 text-slate-200 placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all resize-none text-sm leading-relaxed ${isBulkMode ? 'font-mono' : ''}`}
                                disabled={isGenerating}
                            />
                            {isBulkMode && promptsCount > 0 && (
                            <div className="absolute bottom-3 right-3 bg-indigo-600/20 text-indigo-400 text-[10px] font-bold px-2 py-0.5 rounded border border-indigo-500/30">
                                {promptsCount} PROMPTS
                            </div>
                            )}
                        </div>

                        <div className="mt-4">
                            <Button 
                                onClick={handleGenerate} 
                                isLoading={isGenerating} 
                                disabled={activeTab === 'remix' && !remixImage}
                                className="w-full h-12 text-lg shadow-indigo-500/20"
                            >
                                {isGenerating 
                                ? `Generating ${isBulkMode ? promptsCount : config.batchSize} Images...` 
                                : isBulkMode ? `Generate ${promptsCount} Bulk Images` : `Generate ${config.batchSize} Variations`}
                            </Button>
                        </div>
                    </div>

                    {/* Settings Panel */}
                    <SettingsPanel config={config} onChange={setConfig} disabled={isGenerating || isBulkMode} />
                </div>

                {/* SECTION 2: RESULTS */}
                {(generatedBatch.length > 0 || isGenerating) && (
                    <div className="space-y-6 pt-8 border-t border-slate-800">
                        <div className="flex items-center justify-between">
                            <h3 className="text-lg font-bold text-white">Generation Results</h3>
                            <span className="text-xs text-slate-500 font-mono">
                                {generatedBatch.length} items
                            </span>
                        </div>

                        {/* Main Display Area */}
                        <div className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800">
                            <ImageDisplay 
                                image={selectedImage} 
                                isGenerating={isGenerating} 
                                batchSize={isBulkMode ? promptsCount : config.batchSize}
                                onEdit={selectedImage ? () => setIsEditing(true) : undefined}
                            />
                        </div>

                        {/* Gallery Grid */}
                        {generatedBatch.length > 0 && (
                            <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-3">
                                {generatedBatch.map((img) => (
                                    <button
                                        key={img.id}
                                        onClick={() => setSelectedImageId(img.id)}
                                        className={`relative aspect-square rounded-lg overflow-hidden border-2 transition-all ${selectedImageId === img.id ? 'border-indigo-500 ring-2 ring-indigo-500/30' : 'border-slate-700 hover:border-slate-500'}`}
                                    >
                                        <img src={img.url} alt="Result" className="w-full h-full object-cover" />
                                        {selectedImageId === img.id && (
                                            <div className="absolute inset-0 bg-indigo-500/10 pointer-events-none"></div>
                                        )}
                                    </button>
                                ))}
                                {/* Loading Placeholders */}
                                {isGenerating && Array(Math.max(0, (isBulkMode ? promptsCount : config.batchSize) - generatedBatch.length)).fill(null).map((_, i) => (
                                    <div key={i} className="aspect-square rounded-lg bg-slate-800/50 border-2 border-slate-700/50 border-dashed flex items-center justify-center animate-pulse">
                                        <div className="w-4 h-4 border-2 border-slate-600 border-t-transparent rounded-full animate-spin"></div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}
            </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { AspectRatio, ImageSize, GenerationConfig, GeneratedImage, GenerationSession, RemixMode, RemixConfig } from './types';
import { checkApiKey, promptForApiKey, generateImageFromPrompt, describeImage, generateRemix } from './services/geminiService';
import { SettingsPanel } from './components/SettingsPanel';
import { ImageDisplay } from './components/ImageDisplay';
import { ImageEditor } from './components/ImageEditor';
import { Button } from './components/Button';
import { HistorySidebar } from './components/HistorySidebar';

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState<boolean>(false);

  // Tab State
  const [activeTab, setActiveTab] = useState<RemixMode>('text-to-image');

  // Generation State
  const [prompt, setPrompt] = useState<string>('');
