                    <Button variant="ghost" onClick={() => setIsEditing(false)} className="text-xs">
                        Back to Results
                    </Button>
                </div>
                <ImageEditor 
                    imageUrl={selectedImage.url} 
                    onSave={(url) => {
                        setGeneratedBatch(prev => prev.map(img => img.id === selectedImageId ? {...img, url} : img));
                        setIsEditing(false);
                    }} 
                    onCancel={() => setIsEditing(false)} 
                />
            </div>
        ) : (
            <div className="space-y-8">
                {/* SECTION 1: RESULTS (Moved to Top) */}
                <div className="space-y-6 pb-8 border-b border-slate-800">
                    {/* Main Display Area */}
                    <div className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800 shadow-2xl">
                        <ImageDisplay 
                            image={selectedImage} 
                            isGenerating={isGenerating} 
                            batchSize={isBulkMode ? promptsCount : config.batchSize}
                            onEdit={selectedImage ? () => setIsEditing(true) : undefined}
                        />
                    </div>

                    {/* Gallery Grid */}
                    {(generatedBatch.length > 0 || isGenerating) && (
                        <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-3 animate-fade-in">
                            {generatedBatch.map((img) => (
                                <button
                                    key={img.id}
                                    onClick={() => setSelectedImageId(img.id)}
                                    className={`relative aspect-square rounded-lg overflow-hidden border-2 transition-all ${selectedImageId === img.id ? 'border-indigo-500 ring-2 ring-indigo-500/30' : 'border-slate-700 hover:border-slate-500'}`}
                                >
                                    <img src={img.url} alt="Result" className="w-full h-full object-cover" />
                                    {selectedImageId === img.id && (
                                        <div className="absolute inset-0 bg-indigo-500/10 pointer-events-none"></div>
                                    )}
                                </button>
                            ))}
                            {/* Loading Placeholders */}
                            {isGenerating && Array(Math.max(0, (isBulkMode ? promptsCount : config.batchSize) - generatedBatch.length)).fill(null).map((_, i) => (
                                <div key={i} className="aspect-square rounded-lg bg-slate-800/50 border-2 border-slate-700/50 border-dashed flex items-center justify-center animate-pulse">
                                    <div className="w-4 h-4 border-2 border-slate-600 border-t-transparent rounded-full animate-spin"></div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* SECTION 2: INPUTS (Moved to Bottom) */}
                <div className="space-y-6">
                    {/* Remix Reference Upload */}
                    {activeTab === 'remix' && (
                        <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl space-y-4">
                            <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-wider">Reference Image</h3>
                            <div className="relative border-2 border-dashed border-slate-600 rounded-lg p-6 flex flex-col items-center justify-center bg-slate-900/50 hover:bg-slate-900 transition group">
                                {remixImage ? (
                                    <div className="relative w-full aspect-video max-h-[300px]">
                                        <img src={remixImage} alt="Reference" className="w-full h-full object-contain rounded-md" />
                                        <button onClick={(e) => { e.preventDefault(); setRemixImage(null); }} className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white rounded-full p-1 transition">×</button>
                                        {isAnalyzing && (
                                            <div className="absolute inset-0 flex items-center justify-center bg-black/50 backdrop-blur-sm rounded-md">
                                                <div className="w-6 h-6 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                                            </div>
                                        )}
                                    </div>
                                ) : (
                                    <>
                                        <p className="text-sm text-slate-400">Click to upload reference</p>
                                        <input type="file" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept="image/*" onChange={handleRemixUpload} />
                                    </>
                                )}
                            </div>
                        </div>
                    )}

                    {/* Prompt Input Area */}
                    <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl">
                        <div className="flex items-center justify-between mb-2">
                            <label htmlFor="prompt" className="block text-sm font-semibold text-indigo-400">
                                {activeTab === 'remix' ? 'Description & Modifiers' : 'Creative Prompt'}
                            </label>
                            {activeTab === 'text-to-image' && (
                                <button 
                                onClick={() => setIsBulkMode(!isBulkMode)}
                                className={`text-[10px] px-2 py-0.5 rounded border transition-colors ${isBulkMode ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-700 border-slate-600 text-slate-400'}`}
                                >
                                {isBulkMode ? 'Bulk Mode: ON' : 'Bulk Mode: OFF'}
                                </button>
                            )}
                        </div>
                        <div className="relative">
                            <textarea
                                id="prompt"
                                value={prompt}
                                onChange={(e) => setPrompt(e.target.value)}
                                placeholder={isBulkMode ? "Enter each prompt on a new line..." : "Describe your imagination..."}
                                className={`w-full h-32 bg-slate-900/80 border border-slate-700 rounded-lg p-3 text-slate-200 placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all resize-none text-sm leading-relaxed ${isBulkMode ? 'font-mono' : ''}`}
                                disabled={isGenerating}
                            />
                            {isBulkMode && promptsCount > 0 && (
                            <div className="absolute bottom-3 right-3 bg-indigo-600/20 text-indigo-400 text-[10px] font-bold px-2 py-0.5 rounded border border-indigo-500/30">
                                {promptsCount} PROMPTS
                            </div>
                            )}
                        </div>

                        <div className="mt-4">
                            <Button 
                                onClick={handleGenerate} 
                                isLoading={isGenerating} 
                                disabled={activeTab === 'remix' && !remixImage}
                                className="w-full h-12 text-lg shadow-indigo-500/20"
                            >
                                {isGenerating 
                                ? `Generating ${isBulkMode ? promptsCount : config.batchSize} Images...` 
                                : isBulkMode ? `Generate ${promptsCount} Bulk Images` : `Generate ${config.batchSize} Variations`}
                            </Button>
                        </div>
                    </div>

                    {/* Settings Panel */}
                    <SettingsPanel config={config} onChange={setConfig} disabled={isGenerating || isBulkMode} />
                </div>
            </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { AspectRatio, ImageSize, GenerationConfig, GeneratedImage, GenerationSession, RemixMode, RemixConfig } from './types';
import { checkApiKey, promptForApiKey, generateImageFromPrompt, describeImage, generateRemix } from './services/geminiService';
import { SettingsPanel } from './components/SettingsPanel';
import { ImageDisplay } from './components/ImageDisplay';
import { ImageEditor } from './components/ImageEditor';
import { Button } from './components/Button';
import { HistorySidebar } from './components/HistorySidebar';

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState<boolean>(false);

  // Tab State
  const [activeTab, setActiveTab] = useState<RemixMode>('text-to-image');

  // Generation State
  const [prompt, setPrompt] = useState<string>('');
  const [isBulkMode, setIsBulkMode] = useState<boolean>(false);
  const [isGenerating, setIsGenerating] = useState<boolean>(false);

  // Remix State
  const [remixImage, setRemixImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [remixConfig, setRemixConfig] = useState<RemixConfig>({
      creativity: 0.2,
      structureMatch: true,
      characterMatch: false
  });

  // Batch State
  const [generatedBatch, setGeneratedBatch] = useState<GeneratedImage[]>([]);
  const [selectedImageId, setSelectedImageId] = useState<string | null>(null);

  const [config, setConfig] = useState<GenerationConfig>({
    aspectRatio: AspectRatio.Square,
    imageSize: ImageSize.OneK,
    batchSize: 4 
  });

  // Editor State
  const [isEditing, setIsEditing] = useState<boolean>(false);

  // History State
  const [history, setHistory] = useState<GenerationSession[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState<boolean>(false);

  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const hasKey = await checkApiKey();
        setApiKeyReady(hasKey);
      } catch (e) {
        console.error("Failed to check API key status", e);
      }
    };
    initAuth();
  }, []);

  useEffect(() => {
    const savedPrompt = localStorage.getItem('draft_prompt');
    if (savedPrompt) setPrompt(savedPrompt);

    try {
        const savedHistory = localStorage.getItem('app_history');
        if (savedHistory) setHistory(JSON.parse(savedHistory));
    } catch (e) {
        console.error("Failed to load history", e);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('draft_prompt', prompt);
  }, [prompt]);

  useEffect(() => {
    try {
        localStorage.setItem('app_history', JSON.stringify(history));
    } catch (e) {
        if (history.length > 10) {
            const trimmed = history.slice(0, 10);
            setHistory(trimmed);
        }
    }
  }, [history]);

  const handleConnectKey = async () => {
    try {
      await promptForApiKey();
      setApiKeyReady(true);
      setError(null);
    } catch (e) {
      setError("Failed to connect API Key.");
    }
  };

  const selectedImage = generatedBatch.find(img => img.id === selectedImageId) || null;

  const addToHistory = (batch: GeneratedImage[]) => {
      const newSession: GenerationSession = {
          id: Date.now().toString(),
          prompt: isBulkMode ? `${batch.length} multiple prompts` : prompt,
          images: batch,
          timestamp: Date.now(),
          config: { ...config }
      };
      setHistory(prev => [newSession, ...prev]);
  };

  const handleSelectSession = (session: GenerationSession) => {
      setPrompt(session.prompt);
      setConfig(session.config);
      setGeneratedBatch(session.images);
      if (session.images.length > 0) setSelectedImageId(session.images[0].id);
      setIsEditing(false);
  };

  const handleClearHistory = () => {
      if (confirm("Are you sure?")) {
          setHistory([]);
          localStorage.removeItem('app_history');
      }
  };

  const handleRemixUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = async (event) => {
          const result = event.target?.result as string;
          setRemixImage(result);
          setIsAnalyzing(true);
          try {
             const description = await describeImage(result);
             setPrompt(description);
          } catch (err) {
              setError("Could not analyze image.");
          } finally {
              setIsAnalyzing(false);
          }
      };
      reader.readAsDataURL(file);
  };

  const handleGenerate = async () => {
    if (!prompt.trim()) {
      setError("Please enter at least one prompt.");
      return;
    }

    if (!apiKeyReady) {
        await handleConnectKey();
        return;
    }

    // Determine tasks
    let promptTasks: string[] = [];
    if (isBulkMode && activeTab === 'text-to-image') {
        promptTasks = prompt.split('\n').map(p => p.trim()).filter(p => p.length > 0);
    } else {
        // If not bulk mode, we generate 'batchSize' images for the single prompt
        promptTasks = Array(config.batchSize).fill(prompt);
    }

    if (promptTasks.length === 0) return;

    setIsGenerating(true);
    setIsEditing(false);
    setError(null);
    setGeneratedBatch([]); 
    setSelectedImageId(null);

    const successfulImages: GeneratedImage[] = [];

    try {
      const promises = promptTasks.map(async (taskPrompt, index) => {
        try {
          let imageUrl = "";
          if (activeTab === 'remix' && remixImage) {
              imageUrl = await generateRemix(remixImage, taskPrompt, remixConfig, config);
          } else {
              imageUrl = await generateImageFromPrompt(taskPrompt, config);
          }

          const newImg: GeneratedImage = {
            id: `${Date.now()}-${index}`,
            url: imageUrl,
            prompt: taskPrompt,
            config: { ...config },
            timestamp: Date.now()
          };

          setGeneratedBatch(prev => {
              const updated = [...prev, newImg];
              if (updated.length === 1) setSelectedImageId(newImg.id);
              return updated;
          });

          successfulImages.push(newImg);
        } catch (e) {
          console.error(`Prompt "${taskPrompt}" failed:`, e);
        }
      });

      await Promise.allSettled(promises);

      if (successfulImages.length === 0) {
        throw new Error("Failed to generate any images. Check your connection or API key.");
      }

      addToHistory(successfulImages);

    } catch (err: any) {
      setError(err.message || "Something went wrong.");
    } finally {
      setIsGenerating(false);
    }
  };

  const promptsCount = prompt.split('\n').filter(p => p.trim().length > 0).length;

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 pb-12 font-sans overflow-x-hidden">
      <header className="border-b border-slate-800 bg-[#0f172a]/95 sticky top-0 z-30 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <span className="text-white font-bold text-lg">N</span>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">
              Nano Banana Pro
            </h1>
          </div>

          <div className="hidden md:flex space-x-1 bg-slate-800/50 p-1 rounded-lg border border-slate-700">
             <button onClick={() => setActiveTab('text-to-image')} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'text-to-image' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Text to Image
             </button>
             <button onClick={() => setActiveTab('remix')} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'remix' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Image Remix
             </button>
          </div>

          <div className="flex items-center gap-3">
            {!apiKeyReady ? (
              <Button onClick={handleConnectKey} variant="secondary" className="text-xs">Connect API Key</Button>
            ) : (
              <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-xs font-medium text-emerald-500 hidden sm:inline">System Ready</span>
              </div>
            )}
            <button onClick={() => setIsHistoryOpen(true)} className="p-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-300 transition relative">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      <HistorySidebar 
        isOpen={isHistoryOpen} 
        onClose={() => setIsHistoryOpen(false)} 
        history={history}
        onSelectSession={handleSelectSession}
        onClearHistory={handleClearHistory}
      />

      {/* Main Single Column Layout - Full Width */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 animate-fade-in">

        {error && (
          <div className="mb-6 p-4 rounded-lg bg-red-900/20 border border-red-900/50 flex items-start gap-3">
            <div className="flex-1 text-sm text-red-200">{error}</div>
            <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">×</button>
          </div>
        )}

        {isEditing && selectedImage ? (
            <div className="space-y-4">
                <div className="flex justify-between items-center mb-2">
                    <h2 className="text-lg font-semibold text-white">Editor Studio</h2>
                    <Button variant="ghost" onClick={() => setIsEditing(false)} className="text-xs">
                        Back to Results
                    </Button>
                </div>
                <ImageEditor 
                    imageUrl={selectedImage.url} 
                    onSave={(url) => {
                        setGeneratedBatch(prev => prev.map(img => img.id === selectedImageId ? {...img, url} : img));
                        setIsEditing(false);
                    }} 
                    onCancel={() => setIsEditing(false)} 
                />
            </div>
        ) : (
            <div className="space-y-8">
                {/* SECTION 1: RESULTS (Top - Full Width) */}
                <div className="space-y-6 pb-8 border-b border-slate-800">
                    {/* Main Display Area */}
                    <div className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800 shadow-2xl">
                        <ImageDisplay 
                            image={selectedImage} 
                            isGenerating={isGenerating} 
                            batchSize={isBulkMode ? promptsCount : config.batchSize}
                            onEdit={selectedImage ? () => setIsEditing(true) : undefined}
                        />
                    </div>

                    {/* Gallery Grid */}
                    {(generatedBatch.length > 0 || isGenerating) && (
                        <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 lg:grid-cols-8 gap-3 animate-fade-in">
                            {generatedBatch.map((img) => (
                                <button
                                    key={img.id}
                                    onClick={() => setSelectedImageId(img.id)}
                                    className={`relative aspect-square rounded-lg overflow-hidden border-2 transition-all ${selectedImageId === img.id ? 'border-indigo-500 ring-2 ring-indigo-500/30' : 'border-slate-700 hover:border-slate-500'}`}
                                >
                                    <img src={img.url} alt="Result" className="w-full h-full object-cover" />
                                    {selectedImageId === img.id && (
                                        <div className="absolute inset-0 bg-indigo-500/10 pointer-events-none"></div>
                                    )}
                                </button>
                            ))}
                            {/* Loading Placeholders */}
                            {isGenerating && Array(Math.max(0, (isBulkMode ? promptsCount : config.batchSize) - generatedBatch.length)).fill(null).map((_, i) => (
                                <div key={i} className="aspect-square rounded-lg bg-slate-800/50 border-2 border-slate-700/50 border-dashed flex items-center justify-center animate-pulse">
                                    <div className="w-4 h-4 border-2 border-slate-600 border-t-transparent rounded-full animate-spin"></div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* SECTION 2: INPUTS (Bottom - Full Width) */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    <div className="lg:col-span-2 space-y-6">
                        {/* Remix Reference Upload */}
                        {activeTab === 'remix' && (
                            <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl space-y-4">
                                <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-wider">Reference Image</h3>
                                <div className="relative border-2 border-dashed border-slate-600 rounded-lg p-6 flex flex-col items-center justify-center bg-slate-900/50 hover:bg-slate-900 transition group">
                                    {remixImage ? (
                                        <div className="relative w-full aspect-video max-h-[300px]">
                                            <img src={remixImage} alt="Reference" className="w-full h-full object-contain rounded-md" />
                                            <button onClick={(e) => { e.preventDefault(); setRemixImage(null); }} className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white rounded-full p-1 transition">×</button>
                                            {isAnalyzing && (
                                                <div className="absolute inset-0 flex items-center justify-center bg-black/50 backdrop-blur-sm rounded-md">
                                                    <div className="w-6 h-6 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                                                </div>
                                            )}
                                        </div>
                                    ) : (
                                        <>
                                            <p className="text-sm text-slate-400">Click to upload reference</p>
                                            <input type="file" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept="image/*" onChange={handleRemixUpload} />
                                        </>
                                    )}
                                </div>
                            </div>
                        )}

                        {/* Prompt Input Area */}
                        <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl h-full flex flex-col">
                            <div className="flex items-center justify-between mb-2">
                                <label htmlFor="prompt" className="block text-sm font-semibold text-indigo-400">
                                    {activeTab === 'remix' ? 'Description & Modifiers' : 'Creative Prompt'}
                                </label>
                                {activeTab === 'text-to-image' && (
                                    <button 
                                    onClick={() => setIsBulkMode(!isBulkMode)}
                                    className={`text-[10px] px-2 py-0.5 rounded border transition-colors ${isBulkMode ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-700 border-slate-600 text-slate-400'}`}
                                    >
                                    {isBulkMode ? 'Bulk Mode: ON' : 'Bulk Mode: OFF'}
                                    </button>
                                )}
                            </div>
                            <div className="relative flex-1">
                                <textarea
                                    id="prompt"
                                    value={prompt}
                                    onChange={(e) => setPrompt(e.target.value)}
                                    placeholder={isBulkMode ? "Enter each prompt on a new line..." : "Describe your imagination..."}
                                    className={`w-full h-full min-h-[120px] bg-slate-900/80 border border-slate-700 rounded-lg p-3 text-slate-200 placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all resize-none text-sm leading-relaxed ${isBulkMode ? 'font-mono' : ''}`}
                                    disabled={isGenerating}
                                />
                                {isBulkMode && promptsCount > 0 && (
                                <div className="absolute bottom-3 right-3 bg-indigo-600/20 text-indigo-400 text-[10px] font-bold px-2 py-0.5 rounded border border-indigo-500/30">
                                    {promptsCount} PROMPTS
                                </div>
                                )}
                            </div>
                        </div>
                    </div>

                    <div className="lg:col-span-1 flex flex-col gap-6">
                         {/* Settings Panel */}
                        <SettingsPanel config={config} onChange={setConfig} disabled={isGenerating || isBulkMode} />

                        <Button 
                            onClick={handleGenerate} 
                            isLoading={isGenerating} 
                            disabled={activeTab === 'remix' && !remixImage}
                            className="w-full h-16 text-lg font-bold shadow-indigo-500/20"
                        >
                            {isGenerating 
                            ? `Generating...` 
                            : isBulkMode ? `Generate ${promptsCount} Batch` : `Generate ${config.batchSize} Variations`}
                        </Button>
                    </div>
                </div>
            </div>
        )}
      </main>
    </div>
  );
};

export default App;

export enum AspectRatio {
  Square = "1:1",
  Portrait = "3:4",
  Landscape = "4:3",
  WidePortrait = "9:16",
  WideLandscape = "16:9"
}

export enum ImageSize {
  OneK = "1K",
  TwoK = "2K",
  FourK = "4K"
}

export interface GenerationConfig {
  aspectRatio: AspectRatio;
  imageSize: ImageSize;
  batchSize: number;
}

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  config: GenerationConfig;
  timestamp: number;
}

export interface GenerationSession {
  id: string;
  prompt: string;
  images: GeneratedImage[];
  timestamp: number;
  config: GenerationConfig;
}

export interface ImageFilters {
  brightness: number;
  contrast: number;
  saturation: number;
  grayscale: number;
  sepia: number;
  blur: number;
}

// --- Remix Types ---

export type RemixMode = 'text-to-image' | 'remix';

export interface RemixConfig {
  creativity: number; // 0.1 to 1.0
  structureMatch: boolean;
  characterMatch: boolean;
}

// --- Workspace / Dashboard Type ---

export interface Workspace {
  id: string;
  name: string;
  activeTab: RemixMode;
  prompt: string;
  isGenerating: boolean;

  // Remix State per workspace
  remixImage: string | null;
  remixConfig: RemixConfig;

  // Results per workspace
  generatedBatch: GeneratedImage[];
  selectedImageId: string | null;

  // Config per workspace
  config: GenerationConfig;
}

// --- Layer System Types ---

export type LayerType = 'base' | 'text' | 'image';

export interface BaseLayer {
  id: string;
  type: 'base';
  url: string; // The original generated image
  visible: boolean;
  filters: ImageFilters;
}

export interface TextLayer {
  id: string;
  type: 'text';
  text: string;
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number; // degrees
  fontSize: number;
  fontFamily: string;
  fontWeight: string;
  color: string; // Hex or rgba
  gradient?: {
    enabled: boolean;
    colors: string[]; // [startColor, endColor]
    direction: 'horizontal' | 'vertical';
  };
  visible: boolean;
}

export interface ImageLayer {
  id: string;
  type: 'image';
  url: string;
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number;
  visible: boolean;
  opacity: number;
}

export type Layer = BaseLayer | TextLayer | ImageLayer;

import React, { useState, useEffect } from 'react';
import { AspectRatio, ImageSize, GenerationConfig, GeneratedImage, GenerationSession, RemixMode, RemixConfig, Workspace } from './types';
import { checkApiKey, promptForApiKey, generateImageFromPrompt, describeImage, generateRemix } from './services/geminiService';
import { SettingsPanel } from './components/SettingsPanel';
import { ImageDisplay } from './components/ImageDisplay';
import { ImageEditor } from './components/ImageEditor';
import { Button } from './components/Button';
import { HistorySidebar } from './components/HistorySidebar';

// Default configuration for new workspaces
const DEFAULT_CONFIG: GenerationConfig = {
  aspectRatio: AspectRatio.Square,
  imageSize: ImageSize.OneK,
  batchSize: 4
};

const DEFAULT_REMIX_CONFIG: RemixConfig = {
  creativity: 0.2,
  structureMatch: true,
  characterMatch: false
};

const createNewWorkspace = (index: number): Workspace => ({
  id: `ws-${Date.now()}`,
  name: `Dashboard ${index + 1}`,
  activeTab: 'text-to-image',
  prompt: '',
  isGenerating: false,
  remixImage: null,
  remixConfig: { ...DEFAULT_REMIX_CONFIG },
  generatedBatch: [],
  selectedImageId: null,
  config: { ...DEFAULT_CONFIG }
});

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState<boolean>(false);

  // Workspace State
  const [workspaces, setWorkspaces] = useState<Workspace[]>([createNewWorkspace(0)]);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>(workspaces[0].id);
  const [editingNameId, setEditingNameId] = useState<string | null>(null);

  // Editor State (Global modal)
  const [isEditing, setIsEditing] = useState<boolean>(false);

  // History State (Global)
  const [history, setHistory] = useState<GenerationSession[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState<boolean>(false);

  const [error, setError] = useState<string | null>(null);

  // Helpers to get/set active workspace
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateActiveWorkspace = (updates: Partial<Workspace>) => {
    setWorkspaces(prev => prev.map(w => 
      w.id === activeWorkspaceId ? { ...w, ...updates } : w
    ));
  };

  useEffect(() => {
    const initAuth = async () => {
      try {
        const hasKey = await checkApiKey();
        setApiKeyReady(hasKey);
      } catch (e) {
        console.error("Failed to check API key status", e);
      }
    };
    initAuth();
  }, []);

  // Load/Save Workspaces & History
  useEffect(() => {
    try {
        const savedHistory = localStorage.getItem('app_history');
        if (savedHistory) setHistory(JSON.parse(savedHistory));

        const savedWorkspaces = localStorage.getItem('app_workspaces');
        if (savedWorkspaces) {
            const parsed = JSON.parse(savedWorkspaces);
            if (Array.isArray(parsed) && parsed.length > 0) {
                setWorkspaces(parsed);
                setActiveWorkspaceId(parsed[0].id);
            }
        }
    } catch (e) {
        console.error("Failed to load local data", e);
    }
  }, []);

  useEffect(() => {
    try {
        localStorage.setItem('app_history', JSON.stringify(history));
    } catch (e) {
        if (history.length > 10) {
            const trimmed = history.slice(0, 10);
            setHistory(trimmed);
        }
    }
  }, [history]);

  useEffect(() => {
    try {
        localStorage.setItem('app_workspaces', JSON.stringify(workspaces));
    } catch (e) {
        console.error("Failed to save workspaces", e);
    }
  }, [workspaces]);


  // --- Workspace Actions ---

  const addWorkspace = () => {
    const newWs = createNewWorkspace(workspaces.length);
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  const removeWorkspace = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (workspaces.length === 1) return; // Prevent deleting last one

    const newWorkspaces = workspaces.filter(w => w.id !== id);
    setWorkspaces(newWorkspaces);
    if (activeWorkspaceId === id) {
        setActiveWorkspaceId(newWorkspaces[0].id);
    }
  };

  const handleNameEdit = (id: string, newName: string) => {
      setWorkspaces(prev => prev.map(w => w.id === id ? { ...w, name: newName } : w));
  };


  // --- Logic ---

  const handleConnectKey = async () => {
    try {
      await promptForApiKey();
      setApiKeyReady(true);
      setError(null);
    } catch (e) {
      setError("Failed to connect API Key.");
    }
  };

  const activeImage = activeWorkspace.generatedBatch.find(img => img.id === activeWorkspace.selectedImageId) || null;

  const addToHistory = (batch: GeneratedImage[], currentWs: Workspace) => {
      const newSession: GenerationSession = {
          id: Date.now().toString(),
          prompt: currentWs.prompt,
          images: batch,
          timestamp: Date.now(),
          config: { ...currentWs.config }
      };
      setHistory(prev => [newSession, ...prev]);
  };

  const handleSelectSession = (session: GenerationSession) => {
      // Load session into active workspace
      updateActiveWorkspace({
          prompt: session.prompt,
          config: session.config,
          generatedBatch: session.images,
          selectedImageId: session.images.length > 0 ? session.images[0].id : null
      });
      setIsEditing(false);
  };

  const handleClearHistory = () => {
      if (confirm("Are you sure?")) {
          setHistory([]);
          localStorage.removeItem('app_history');
      }
  };

  const handleRemixUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = async (event) => {
          const result = event.target?.result as string;
          updateActiveWorkspace({ remixImage: result });

          // Auto analyze
          try {
             const description = await describeImage(result);
             updateActiveWorkspace({ prompt: description });
          } catch (err) {
              setError("Could not analyze image.");
          }
      };
      reader.readAsDataURL(file);
  };

  const handleGenerate = async () => {
    if (!activeWorkspace.prompt.trim()) {
      setError("Please enter a prompt.");
      return;
    }

    if (!apiKeyReady) {
        await handleConnectKey();
        return;
    }

    updateActiveWorkspace({ isGenerating: true, generatedBatch: [], selectedImageId: null });
    setIsEditing(false);
    setError(null);

    const successfulImages: GeneratedImage[] = [];
    const promptTasks = Array(activeWorkspace.config.batchSize).fill(activeWorkspace.prompt);

    try {
      const promises = promptTasks.map(async (taskPrompt, index) => {
        try {
          let imageUrl = "";
          if (activeWorkspace.activeTab === 'remix' && activeWorkspace.remixImage) {
              imageUrl = await generateRemix(activeWorkspace.remixImage, taskPrompt, activeWorkspace.remixConfig, activeWorkspace.config);
          } else {
              imageUrl = await generateImageFromPrompt(taskPrompt, activeWorkspace.config);
          }

          const newImg: GeneratedImage = {
            id: `${Date.now()}-${index}`,
            url: imageUrl,
            prompt: taskPrompt,
            config: { ...activeWorkspace.config },
            timestamp: Date.now()
          };

          // Functional update to avoid closure staleness issues with async map
          setWorkspaces(prev => prev.map(w => {
              if (w.id === activeWorkspaceId) {
                  const updatedBatch = [...w.generatedBatch, newImg];
                  return {
                      ...w,
                      generatedBatch: updatedBatch,
                      selectedImageId: updatedBatch.length === 1 ? newImg.id : w.selectedImageId
                  };
              }
              return w;
          }));

          successfulImages.push(newImg);
        } catch (e) {
          console.error(`Prompt "${taskPrompt}" failed:`, e);
        }
      });

      await Promise.allSettled(promises);

      if (successfulImages.length === 0) {
        throw new Error("Failed to generate any images. Check your connection or API key.");
      }

      addToHistory(successfulImages, activeWorkspace);

    } catch (err: any) {
      setError(err.message || "Something went wrong.");
    } finally {
        updateActiveWorkspace({ isGenerating: false });
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 pb-12 font-sans overflow-x-hidden flex flex-col">
      <header className="border-b border-slate-800 bg-[#0f172a]/95 z-30 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <span className="text-white font-bold text-lg">N</span>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">
              Nano Banana Pro
            </h1>
          </div>

          <div className="hidden md:flex space-x-1 bg-slate-800/50 p-1 rounded-lg border border-slate-700">
             <button onClick={() => updateActiveWorkspace({ activeTab: 'text-to-image' })} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeWorkspace.activeTab === 'text-to-image' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Text to Image
             </button>
             <button onClick={() => updateActiveWorkspace({ activeTab: 'remix' })} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeWorkspace.activeTab === 'remix' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Image Remix
             </button>
          </div>

          <div className="flex items-center gap-3">
            {!apiKeyReady ? (
              <Button onClick={handleConnectKey} variant="secondary" className="text-xs">Connect API Key</Button>
            ) : (
              <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-xs font-medium text-emerald-500 hidden sm:inline">System Ready</span>
              </div>
            )}
            <button onClick={() => setIsHistoryOpen(true)} className="p-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-300 transition relative">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      {/* Dashboard Tabs */}
      <div className="bg-[#0f172a] border-b border-slate-800 sticky top-0 z-20">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex items-end gap-1 overflow-x-auto no-scrollbar">
              {workspaces.map((ws) => (
                  <div 
                    key={ws.id}
                    onClick={() => setActiveWorkspaceId(ws.id)}
                    className={`
                        group relative flex items-center gap-2 px-4 py-2.5 min-w-[140px] max-w-[200px] cursor-pointer border-b-2 transition-all select-none
                        ${activeWorkspaceId === ws.id 
                            ? 'border-indigo-500 bg-slate-800/50 text-white' 
                            : 'border-transparent text-slate-400 hover:text-slate-200 hover:bg-slate-800/30'}
                    `}
                  >
                      {editingNameId === ws.id ? (
                          <input 
                            autoFocus
                            type="text" 
                            className="bg-slate-900 border border-indigo-500 rounded px-1 py-0.5 text-xs w-full outline-none text-white"
                            value={ws.name}
                            onChange={(e) => handleNameEdit(ws.id, e.target.value)}
                            onBlur={() => setEditingNameId(null)}
                            onKeyDown={(e) => e.key === 'Enter' && setEditingNameId(null)}
                          />
                      ) : (
                        <span className="text-sm font-medium truncate flex-1" onDoubleClick={() => setEditingNameId(ws.id)}>
                            {ws.name}
                        </span>
                      )}

                      {workspaces.length > 1 && (
                          <button 
                            onClick={(e) => removeWorkspace(e, ws.id)}
                            className={`opacity-0 group-hover:opacity-100 p-0.5 hover:bg-red-500/20 hover:text-red-400 rounded-full transition ${activeWorkspaceId === ws.id ? 'opacity-50' : ''}`}
                          >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                                <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                              </svg>
                          </button>
                      )}
                  </div>
              ))}
              <button 
                onClick={addWorkspace}
                className="ml-2 p-2 text-slate-500 hover:text-indigo-400 hover:bg-indigo-500/10 rounded-lg transition"
                title="New Dashboard"
              >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                  </svg>
              </button>
          </div>
      </div>

      <HistorySidebar 
        isOpen={isHistoryOpen} 
        onClose={() => setIsHistoryOpen(false)} 
        history={history}
        onSelectSession={handleSelectSession}
        onClearHistory={handleClearHistory}
      />

      {/* Main Single Column Layout - Full Width - Active Workspace Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 animate-fade-in">

        {error && (
          <div className="mb-6 p-4 rounded-lg bg-red-900/20 border border-red-900/50 flex items-start gap-3">
            <div className="flex-1 text-sm text-red-200">{error}</div>
            <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">×</button>
          </div>
        )}

        {isEditing && activeImage ? (
            <div className="space-y-4">
                <div className="flex justify-between items-center mb-2">
                    <h2 className="text-lg font-semibold text-white">Editor Studio - {activeWorkspace.name}</h2>
                    <Button variant="ghost" onClick={() => setIsEditing(false)} className="text-xs">
                        Back to Results
                    </Button>
                </div>
                <ImageEditor 
                    imageUrl={activeImage.url} 
                    onSave={(url) => {
                         // Update image in the current batch
                         const updatedBatch = activeWorkspace.generatedBatch.map(img => 
                             img.id === activeWorkspace.selectedImageId ? {...img, url} : img
                         );
                         updateActiveWorkspace({ generatedBatch: updatedBatch });
                         setIsEditing(false);
                    }} 
                    onCancel={() => setIsEditing(false)} 
                />
            </div>
        ) : (
            <div className="space-y-8">
                {/* SECTION 1: RESULTS (Top - Full Width) */}
                <div className="space-y-6 pb-8 border-b border-slate-800">
                    {/* Main Display Area */}
                    <div className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800 shadow-2xl">
                        <ImageDisplay 
                            image={activeImage} 
                            isGenerating={activeWorkspace.isGenerating} 
                            batchSize={activeWorkspace.config.batchSize}
                            onEdit={activeImage ? () => setIsEditing(true) : undefined}
                        />
                    </div>

                    {/* Gallery Grid */}
                    {(activeWorkspace.generatedBatch.length > 0 || activeWorkspace.isGenerating) && (
                        <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 lg:grid-cols-8 gap-3 animate-fade-in">
                            {activeWorkspace.generatedBatch.map((img) => (
                                <button
                                    key={img.id}
                                    onClick={() => updateActiveWorkspace({ selectedImageId: img.id })}
                                    className={`relative aspect-square rounded-lg overflow-hidden border-2 transition-all ${activeWorkspace.selectedImageId === img.id ? 'border-indigo-500 ring-2 ring-indigo-500/30' : 'border-slate-700 hover:border-slate-500'}`}
                                >
                                    <img src={img.url} alt="Result" className="w-full h-full object-cover" />
                                    {activeWorkspace.selectedImageId === img.id && (
                                        <div className="absolute inset-0 bg-indigo-500/10 pointer-events-none"></div>
                                    )}
                                </button>
                            ))}
                            {/* Loading Placeholders */}
                            {activeWorkspace.isGenerating && Array(Math.max(0, activeWorkspace.config.batchSize - activeWorkspace.generatedBatch.length)).fill(null).map((_, i) => (
                                <div key={i} className="aspect-square rounded-lg bg-slate-800/50 border-2 border-slate-700/50 border-dashed flex items-center justify-center animate-pulse">
                                    <div className="w-4 h-4 border-2 border-slate-600 border-t-transparent rounded-full animate-spin"></div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* SECTION 2: INPUTS (Bottom - Full Width) */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    <div className="lg:col-span-2 space-y-6">
                        {/* Remix Reference Upload */}
                        {activeWorkspace.activeTab === 'remix' && (
                            <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl space-y-4">
                                <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-wider">Reference Image</h3>
                                <div className="relative border-2 border-dashed border-slate-600 rounded-lg p-6 flex flex-col items-center justify-center bg-slate-900/50 hover:bg-slate-900 transition group">
                                    {activeWorkspace.remixImage ? (
                                        <div className="relative w-full aspect-video max-h-[300px]">
                                            <img src={activeWorkspace.remixImage} alt="Reference" className="w-full h-full object-contain rounded-md" />
                                            <button onClick={(e) => { e.preventDefault(); updateActiveWorkspace({ remixImage: null }); }} className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white rounded-full p-1 transition">×</button>
                                        </div>
                                    ) : (
                                        <>
                                            <p className="text-sm text-slate-400">Click to upload reference</p>
                                            <input type="file" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept="image/*" onChange={handleRemixUpload} />
                                        </>
                                    )}
                                </div>
                            </div>
                        )}

                        {/* Prompt Input Area */}
                        <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl h-full flex flex-col">
                            <div className="flex items-center justify-between mb-2">
                                <label htmlFor="prompt" className="block text-sm font-semibold text-indigo-400">
                                    {activeWorkspace.activeTab === 'remix' ? 'Description & Modifiers' : 'Creative Prompt'}
                                </label>
                            </div>
                            <div className="relative flex-1">
                                <textarea
                                    id="prompt"
                                    value={activeWorkspace.prompt}
                                    onChange={(e) => updateActiveWorkspace({ prompt: e.target.value })}
                                    placeholder="Describe your imagination..."
                                    className="w-full h-full min-h-[120px] bg-slate-900/80 border border-slate-700 rounded-lg p-3 text-slate-200 placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all resize-none text-sm leading-relaxed"
                                    disabled={activeWorkspace.isGenerating}
                                />
                            </div>
                        </div>
                    </div>

                    <div className="lg:col-span-1 flex flex-col gap-6">
                         {/* Settings Panel */}
                        <SettingsPanel 
                            config={activeWorkspace.config} 
                            onChange={(newCfg) => updateActiveWorkspace({ config: newCfg })} 
                            disabled={activeWorkspace.isGenerating} 
                        />

                        <Button 
                            onClick={handleGenerate} 
                            isLoading={activeWorkspace.isGenerating} 
                            disabled={activeWorkspace.activeTab === 'remix' && !activeWorkspace.remixImage}
                            className="w-full h-16 text-lg font-bold shadow-indigo-500/20"
                        >
                            {activeWorkspace.isGenerating 
                            ? `Generating...` 
                            : `Generate ${activeWorkspace.config.batchSize} Variations`}
                        </Button>
                    </div>
                </div>
            </div>
        )}
      </main>
    </div>
  );
};

export default App;

export enum AspectRatio {
  Square = "1:1",
  Portrait = "3:4",
  Landscape = "4:3",
  WidePortrait = "9:16",
  WideLandscape = "16:9"
}

export enum ImageSize {
  OneK = "1K",
  TwoK = "2K",
  FourK = "4K"
}

export interface GenerationConfig {
  aspectRatio: AspectRatio;
  imageSize: ImageSize;
  batchSize: number;
}

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  config: GenerationConfig;
  timestamp: number;
}

export interface GenerationSession {
  id: string;
  prompt: string;
  images: GeneratedImage[];
  timestamp: number;
  config: GenerationConfig;
}

export interface ImageFilters {
  brightness: number;
  contrast: number;
  saturation: number;
  grayscale: number;
  sepia: number;
  blur: number;
}

// --- Remix Types ---

export type RemixMode = 'text-to-image' | 'remix';

export interface RemixConfig {
  creativity: number; // 0.1 to 1.0
  structureMatch: boolean;
  characterMatch: boolean;
}

// --- Workspace / Dashboard Type ---

export type WorkspaceStatus = 'idle' | 'generating' | 'success' | 'error';

export interface Workspace {
  id: string;
  name: string;
  activeTab: RemixMode;
  prompt: string;
  isGenerating: boolean;
  status: WorkspaceStatus; // Added status field for color coding

  // Remix State per workspace
  remixImage: string | null;
  remixConfig: RemixConfig;

  // Results per workspace
  generatedBatch: GeneratedImage[];
  selectedImageId: string | null;

  // Config per workspace
  config: GenerationConfig;
}

// --- Layer System Types ---

export type LayerType = 'base' | 'text' | 'image';

export interface BaseLayer {
  id: string;
  type: 'base';
  url: string; // The original generated image
  visible: boolean;
  filters: ImageFilters;
}

export interface TextLayer {
  id: string;
  type: 'text';
  text: string;
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number; // degrees
  fontSize: number;
  fontFamily: string;
  fontWeight: string;
  color: string; // Hex or rgba
  gradient?: {
    enabled: boolean;
    colors: string[]; // [startColor, endColor]
    direction: 'horizontal' | 'vertical';
  };
  visible: boolean;
}

export interface ImageLayer {
  id: string;
  type: 'image';
  url: string;
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number;
  visible: boolean;
  opacity: number;
}

export type Layer = BaseLayer | TextLayer | ImageLayer;

import React, { useState, useEffect } from 'react';
import { AspectRatio, ImageSize, GenerationConfig, GeneratedImage, GenerationSession, RemixMode, RemixConfig, Workspace, WorkspaceStatus } from './types';
import { checkApiKey, promptForApiKey, generateImageFromPrompt, describeImage, generateRemix } from './services/geminiService';
import { SettingsPanel } from './components/SettingsPanel';
import { ImageDisplay } from './components/ImageDisplay';
import { ImageEditor } from './components/ImageEditor';
import { Button } from './components/Button';
import { HistorySidebar } from './components/HistorySidebar';

// Default configuration for new workspaces
const DEFAULT_CONFIG: GenerationConfig = {
  aspectRatio: AspectRatio.Square,
  imageSize: ImageSize.OneK,
  batchSize: 4
};

const DEFAULT_REMIX_CONFIG: RemixConfig = {
  creativity: 0.2,
  structureMatch: true,
  characterMatch: false
};

const createNewWorkspace = (index: number): Workspace => ({
  id: `ws-${Date.now()}`,
  name: `Dashboard ${index + 1}`,
  activeTab: 'text-to-image',
  prompt: '',
  isGenerating: false,
  status: 'idle',
  remixImage: null,
  remixConfig: { ...DEFAULT_REMIX_CONFIG },
  generatedBatch: [],
  selectedImageId: null,
  config: { ...DEFAULT_CONFIG }
});

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState<boolean>(false);

  // Workspace State
  const [workspaces, setWorkspaces] = useState<Workspace[]>([createNewWorkspace(0)]);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>(workspaces[0].id);
  const [editingNameId, setEditingNameId] = useState<string | null>(null);

  // Editor State (Global modal)
  const [isEditing, setIsEditing] = useState<boolean>(false);

  // History State (Global)
  const [history, setHistory] = useState<GenerationSession[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState<boolean>(false);

  const [error, setError] = useState<string | null>(null);

  // Helpers to get/set active workspace
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateActiveWorkspace = (updates: Partial<Workspace>) => {
    setWorkspaces(prev => prev.map(w => 
      w.id === activeWorkspaceId ? { ...w, ...updates } : w
    ));
  };

  useEffect(() => {
    const initAuth = async () => {
      try {
        const hasKey = await checkApiKey();
        setApiKeyReady(hasKey);
      } catch (e) {
        console.error("Failed to check API key status", e);
      }
    };
    initAuth();
  }, []);

  // Load/Save Workspaces & History
  useEffect(() => {
    try {
        const savedHistory = localStorage.getItem('app_history');
        if (savedHistory) setHistory(JSON.parse(savedHistory));

        const savedWorkspaces = localStorage.getItem('app_workspaces');
        if (savedWorkspaces) {
            const parsed = JSON.parse(savedWorkspaces);
            if (Array.isArray(parsed) && parsed.length > 0) {
                setWorkspaces(parsed);
                setActiveWorkspaceId(parsed[0].id);
            }
        }
    } catch (e) {
        console.error("Failed to load local data", e);
    }
  }, []);

  useEffect(() => {
    try {
        localStorage.setItem('app_history', JSON.stringify(history));
    } catch (e) {
        if (history.length > 10) {
            const trimmed = history.slice(0, 10);
            setHistory(trimmed);
        }
    }
  }, [history]);

  useEffect(() => {
    try {
        localStorage.setItem('app_workspaces', JSON.stringify(workspaces));
    } catch (e) {
        console.error("Failed to save workspaces", e);
    }
  }, [workspaces]);


  // --- Workspace Actions ---

  const addWorkspace = () => {
    const newWs = createNewWorkspace(workspaces.length);
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  const removeWorkspace = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (workspaces.length === 1) return; // Prevent deleting last one

    const newWorkspaces = workspaces.filter(w => w.id !== id);
    setWorkspaces(newWorkspaces);
    if (activeWorkspaceId === id) {
        setActiveWorkspaceId(newWorkspaces[0].id);
    }
  };

  const clearOtherWorkspaces = () => {
      if (workspaces.length <= 1) return;
      if (confirm("Close all other dashboards except the current one?")) {
          setWorkspaces([activeWorkspace]);
      }
  };

  const handleNameEdit = (id: string, newName: string) => {
      setWorkspaces(prev => prev.map(w => w.id === id ? { ...w, name: newName } : w));
  };


  // --- Logic ---

  const handleConnectKey = async () => {
    try {
      await promptForApiKey();
      setApiKeyReady(true);
      setError(null);
    } catch (e) {
      setError("Failed to connect API Key.");
    }
  };

  const activeImage = activeWorkspace.generatedBatch.find(img => img.id === activeWorkspace.selectedImageId) || null;

  const addToHistory = (batch: GeneratedImage[], currentWs: Workspace) => {
      const newSession: GenerationSession = {
          id: Date.now().toString(),
          prompt: currentWs.prompt,
          images: batch,
          timestamp: Date.now(),
          config: { ...currentWs.config }
      };
      setHistory(prev => [newSession, ...prev]);
  };

  const handleSelectSession = (session: GenerationSession) => {
      // Load session into active workspace
      updateActiveWorkspace({
          prompt: session.prompt,
          config: session.config,
          generatedBatch: session.images,
          selectedImageId: session.images.length > 0 ? session.images[0].id : null,
          status: 'success' // restore as success
      });
      setIsEditing(false);
  };

  const handleClearHistory = () => {
      if (confirm("Are you sure?")) {
          setHistory([]);
          localStorage.removeItem('app_history');
      }
  };

  const handleRemixUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = async (event) => {
          const result = event.target?.result as string;
          updateActiveWorkspace({ remixImage: result });

          // Auto analyze
          try {
             const description = await describeImage(result);
             updateActiveWorkspace({ prompt: description });
          } catch (err) {
              setError("Could not analyze image.");
          }
      };
      reader.readAsDataURL(file);
  };

  const handleGenerate = async () => {
    if (!activeWorkspace.prompt.trim()) {
      setError("Please enter a prompt.");
      return;
    }

    if (!apiKeyReady) {
        await handleConnectKey();
        return;
    }

    // Set Status: Generating (Orange)
    updateActiveWorkspace({ 
        isGenerating: true, 
        status: 'generating',
        generatedBatch: [], 
        selectedImageId: null 
    });

    setIsEditing(false);
    setError(null);

    const successfulImages: GeneratedImage[] = [];
    const promptTasks = Array(activeWorkspace.config.batchSize).fill(activeWorkspace.prompt);

    try {
      const promises = promptTasks.map(async (taskPrompt, index) => {
        try {
          let imageUrl = "";
          if (activeWorkspace.activeTab === 'remix' && activeWorkspace.remixImage) {
              imageUrl = await generateRemix(activeWorkspace.remixImage, taskPrompt, activeWorkspace.remixConfig, activeWorkspace.config);
          } else {
              imageUrl = await generateImageFromPrompt(taskPrompt, activeWorkspace.config);
          }

          const newImg: GeneratedImage = {
            id: `${Date.now()}-${index}`,
            url: imageUrl,
            prompt: taskPrompt,
            config: { ...activeWorkspace.config },
            timestamp: Date.now()
          };

          // Functional update to avoid closure staleness issues with async map
          setWorkspaces(prev => prev.map(w => {
              if (w.id === activeWorkspaceId) {
                  const updatedBatch = [...w.generatedBatch, newImg];
                  return {
                      ...w,
                      generatedBatch: updatedBatch,
                      selectedImageId: updatedBatch.length === 1 ? newImg.id : w.selectedImageId
                  };
              }
              return w;
          }));

          successfulImages.push(newImg);
        } catch (e) {
          console.error(`Prompt "${taskPrompt}" failed:`, e);
        }
      });

      await Promise.allSettled(promises);

      if (successfulImages.length === 0) {
        throw new Error("Failed to generate any images. Check your connection or API key.");
      }

      // Set Status: Success (Green)
      updateActiveWorkspace({ isGenerating: false, status: 'success' });
      addToHistory(successfulImages, activeWorkspace);

    } catch (err: any) {
      setError(err.message || "Something went wrong.");
      // Set Status: Error (Red)
      updateActiveWorkspace({ isGenerating: false, status: 'error' });
    }
  };

  // Helper to get tab color class based on status and active state
  const getTabColorClass = (ws: Workspace, isActive: boolean) => {
      if (ws.status === 'generating') return 'border-amber-500 text-amber-500 bg-amber-500/10 animate-pulse';
      if (ws.status === 'error') return isActive ? 'border-red-500 text-red-500 bg-slate-800' : 'border-red-500/50 text-red-700 bg-red-900/10';

      // Success state (Green)
      if (ws.status === 'success') {
          return isActive 
            ? 'border-emerald-500 text-emerald-500 bg-slate-800' 
            : 'border-emerald-500/50 text-emerald-600 bg-emerald-900/10 hover:text-emerald-500';
      }

      // Idle / Default state
      return isActive 
        ? 'border-indigo-500 bg-slate-800/50 text-white' 
        : 'border-transparent text-slate-400 hover:text-slate-200 hover:bg-slate-800/30';
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 pb-12 font-sans overflow-x-hidden flex flex-col">
      <header className="border-b border-slate-800 bg-[#0f172a]/95 z-30 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <span className="text-white font-bold text-lg">N</span>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">
              Nano Banana Pro
            </h1>
          </div>

          <div className="hidden md:flex space-x-1 bg-slate-800/50 p-1 rounded-lg border border-slate-700">
             <button onClick={() => updateActiveWorkspace({ activeTab: 'text-to-image' })} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeWorkspace.activeTab === 'text-to-image' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Text to Image
             </button>
             <button onClick={() => updateActiveWorkspace({ activeTab: 'remix' })} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeWorkspace.activeTab === 'remix' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Image Remix
             </button>
          </div>

          <div className="flex items-center gap-3">
            {!apiKeyReady ? (
              <Button onClick={handleConnectKey} variant="secondary" className="text-xs">Connect API Key</Button>
            ) : (
              <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-xs font-medium text-emerald-500 hidden sm:inline">System Ready</span>
              </div>
            )}
            <button onClick={() => setIsHistoryOpen(true)} className="p-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-300 transition relative">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      {/* Dashboard Tabs */}
      <div className="bg-[#0f172a] border-b border-slate-800 sticky top-0 z-20">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex items-end gap-1 overflow-x-auto no-scrollbar">
              {workspaces.map((ws) => (
                  <div 
                    key={ws.id}
                    onClick={() => setActiveWorkspaceId(ws.id)}
                    className={`
                        group relative flex items-center gap-2 px-4 py-2.5 min-w-[140px] max-w-[200px] cursor-pointer border-b-2 transition-all select-none
                        ${getTabColorClass(ws, activeWorkspaceId === ws.id)}
                    `}
                  >
                      {editingNameId === ws.id ? (
                          <input 
                            autoFocus
                            type="text" 
                            className="bg-slate-900 border border-indigo-500 rounded px-1 py-0.5 text-xs w-full outline-none text-white"
                            value={ws.name}
                            onChange={(e) => handleNameEdit(ws.id, e.target.value)}
                            onBlur={() => setEditingNameId(null)}
                            onKeyDown={(e) => e.key === 'Enter' && setEditingNameId(null)}
                          />
                      ) : (
                        <span className="text-sm font-medium truncate flex-1 flex items-center gap-2" onDoubleClick={() => setEditingNameId(ws.id)}>
                            {/* Status Icon Indicator */}
                            {ws.status === 'generating' && <div className="w-2 h-2 rounded-full bg-amber-500 animate-bounce" />}
                            {ws.status === 'success' && <div className="w-2 h-2 rounded-full bg-emerald-500" />}
                            {ws.status === 'error' && <div className="w-2 h-2 rounded-full bg-red-500" />}
                            {ws.name}
                        </span>
                      )}

                      {workspaces.length > 1 && (
                          <button 
                            onClick={(e) => removeWorkspace(e, ws.id)}
                            className={`opacity-0 group-hover:opacity-100 p-0.5 hover:bg-slate-700 hover:text-red-400 rounded-full transition ${activeWorkspaceId === ws.id ? 'opacity-50' : ''}`}
                          >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                                <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                              </svg>
                          </button>
                      )}
                  </div>
              ))}

              <div className="flex items-center ml-2 border-l border-slate-700 pl-2 gap-1 h-full py-2">
                <button 
                    onClick={addWorkspace}
                    className="p-2 text-slate-500 hover:text-indigo-400 hover:bg-indigo-500/10 rounded-lg transition"
                    title="New Dashboard"
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                    </svg>
                </button>

                {workspaces.length > 1 && (
                    <button 
                        onClick={clearOtherWorkspaces}
                        className="p-2 text-slate-500 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition"
                        title="Close Other Dashboards"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                        </svg>
                    </button>
                )}
              </div>
          </div>
      </div>

      <HistorySidebar 
        isOpen={isHistoryOpen} 
        onClose={() => setIsHistoryOpen(false)} 
        history={history}
        onSelectSession={handleSelectSession}
        onClearHistory={handleClearHistory}
      />

      {/* Main Single Column Layout - Full Width - Active Workspace Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 animate-fade-in">

        {error && (
          <div className="mb-6 p-4 rounded-lg bg-red-900/20 border border-red-900/50 flex items-start gap-3">
            <div className="flex-1 text-sm text-red-200">{error}</div>
            <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">×</button>
          </div>
        )}

        {isEditing && activeImage ? (
            <div className="space-y-4">
                <div className="flex justify-between items-center mb-2">
                    <h2 className="text-lg font-semibold text-white">Editor Studio - {activeWorkspace.name}</h2>
                    <Button variant="ghost" onClick={() => setIsEditing(false)} className="text-xs">
                        Back to Results
                    </Button>
                </div>
                <ImageEditor 
                    imageUrl={activeImage.url} 
                    onSave={(url) => {
                         // Update image in the current batch
                         const updatedBatch = activeWorkspace.generatedBatch.map(img => 
                             img.id === activeWorkspace.selectedImageId ? {...img, url} : img
                         );
                         updateActiveWorkspace({ generatedBatch: updatedBatch });
                         setIsEditing(false);
                    }} 
                    onCancel={() => setIsEditing(false)} 
                />
            </div>
        ) : (
            <div className="space-y-8">
                {/* SECTION 1: RESULTS (Top - Full Width) */}
                <div className="space-y-6 pb-8 border-b border-slate-800">
                    {/* Main Display Area */}
                    <div className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800 shadow-2xl">
                        <ImageDisplay 
                            image={activeImage} 
                            isGenerating={activeWorkspace.isGenerating} 
                            batchSize={activeWorkspace.config.batchSize}
                            onEdit={activeImage ? () => setIsEditing(true) : undefined}
                        />
                    </div>

                    {/* Gallery Grid */}
                    {(activeWorkspace.generatedBatch.length > 0 || activeWorkspace.isGenerating) && (
                        <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 lg:grid-cols-8 gap-3 animate-fade-in">
                            {activeWorkspace.generatedBatch.map((img) => (
                                <button
                                    key={img.id}
                                    onClick={() => updateActiveWorkspace({ selectedImageId: img.id })}
                                    className={`relative aspect-square rounded-lg overflow-hidden border-2 transition-all ${activeWorkspace.selectedImageId === img.id ? 'border-indigo-500 ring-2 ring-indigo-500/30' : 'border-slate-700 hover:border-slate-500'}`}
                                >
                                    <img src={img.url} alt="Result" className="w-full h-full object-cover" />
                                    {activeWorkspace.selectedImageId === img.id && (
                                        <div className="absolute inset-0 bg-indigo-500/10 pointer-events-none"></div>
                                    )}
                                </button>
                            ))}
                            {/* Loading Placeholders */}
                            {activeWorkspace.isGenerating && Array(Math.max(0, activeWorkspace.config.batchSize - activeWorkspace.generatedBatch.length)).fill(null).map((_, i) => (
                                <div key={i} className="aspect-square rounded-lg bg-slate-800/50 border-2 border-slate-700/50 border-dashed flex items-center justify-center animate-pulse">
                                    <div className="w-4 h-4 border-2 border-slate-600 border-t-transparent rounded-full animate-spin"></div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* SECTION 2: INPUTS (Bottom - Full Width) */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    <div className="lg:col-span-2 space-y-6">
                        {/* Remix Reference Upload */}
                        {activeWorkspace.activeTab === 'remix' && (
                            <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl space-y-4">
                                <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-wider">Reference Image</h3>
                                <div className="relative border-2 border-dashed border-slate-600 rounded-lg p-6 flex flex-col items-center justify-center bg-slate-900/50 hover:bg-slate-900 transition group">
                                    {activeWorkspace.remixImage ? (
                                        <div className="relative w-full aspect-video max-h-[300px]">
                                            <img src={activeWorkspace.remixImage} alt="Reference" className="w-full h-full object-contain rounded-md" />
                                            <button onClick={(e) => { e.preventDefault(); updateActiveWorkspace({ remixImage: null }); }} className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white rounded-full p-1 transition">×</button>
                                        </div>
                                    ) : (
                                        <>
                                            <p className="text-sm text-slate-400">Click to upload reference</p>
                                            <input type="file" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept="image/*" onChange={handleRemixUpload} />
                                        </>
                                    )}
                                </div>
                            </div>
                        )}

                        {/* Prompt Input Area */}
                        <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl h-full flex flex-col">
                            <div className="flex items-center justify-between mb-2">
                                <label htmlFor="prompt" className="block text-sm font-semibold text-indigo-400">
                                    {activeWorkspace.activeTab === 'remix' ? 'Description & Modifiers' : 'Creative Prompt'}
                                </label>
                            </div>
                            <div className="relative flex-1">
                                <textarea
                                    id="prompt"
                                    value={activeWorkspace.prompt}
                                    onChange={(e) => updateActiveWorkspace({ prompt: e.target.value })}
                                    placeholder="Describe your imagination..."
                                    className="w-full h-full min-h-[120px] bg-slate-900/80 border border-slate-700 rounded-lg p-3 text-slate-200 placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all resize-none text-sm leading-relaxed"
                                    disabled={activeWorkspace.isGenerating}
                                />
                            </div>
                        </div>
                    </div>

                    <div className="lg:col-span-1 flex flex-col gap-6">
                         {/* Settings Panel */}
                        <SettingsPanel 
                            config={activeWorkspace.config} 
                            onChange={(newCfg) => updateActiveWorkspace({ config: newCfg })} 
                            disabled={activeWorkspace.isGenerating} 
                        />

                        <Button 
                            onClick={handleGenerate} 
                            isLoading={activeWorkspace.isGenerating} 
                            disabled={activeWorkspace.activeTab === 'remix' && !activeWorkspace.remixImage}
                            className="w-full h-16 text-lg font-bold shadow-indigo-500/20"
                        >
                            {activeWorkspace.isGenerating 
                            ? `Generating...` 
                            : `Generate ${activeWorkspace.config.batchSize} Variations`}
                        </Button>
                    </div>
                </div>
            </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { AspectRatio, ImageSize, GenerationConfig, GeneratedImage, GenerationSession, RemixMode, RemixConfig, Workspace, WorkspaceStatus } from './types';
import { checkApiKey, promptForApiKey, generateImageFromPrompt, describeImage, generateRemix } from './services/geminiService';
import { SettingsPanel } from './components/SettingsPanel';
import { ImageDisplay } from './components/ImageDisplay';
import { ImageEditor } from './components/ImageEditor';
import { Button } from './components/Button';
import { HistorySidebar } from './components/HistorySidebar';

// Default configuration for new workspaces
const DEFAULT_CONFIG: GenerationConfig = {
  aspectRatio: AspectRatio.Square,
  imageSize: ImageSize.OneK,
  batchSize: 4
};

const DEFAULT_REMIX_CONFIG: RemixConfig = {
  creativity: 0.2,
  structureMatch: true,
  characterMatch: false
};

const createNewWorkspace = (index: number): Workspace => ({
  id: `ws-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
  name: `Dashboard ${index + 1}`,
  activeTab: 'text-to-image',
  prompt: '',
  isGenerating: false,
  status: 'idle',
  remixImage: null,
  remixConfig: { ...DEFAULT_REMIX_CONFIG },
  generatedBatch: [],
  selectedImageId: null,
  config: { ...DEFAULT_CONFIG }
});

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState<boolean>(false);

  // Workspace State
  const [workspaces, setWorkspaces] = useState<Workspace[]>([createNewWorkspace(0)]);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>(workspaces[0].id);
  const [editingNameId, setEditingNameId] = useState<string | null>(null);

  // Delete Mode State
  const [isDeleteMode, setIsDeleteMode] = useState<boolean>(false);
  const [deleteSelection, setDeleteSelection] = useState<Set<string>>(new Set());

  // Editor State (Global modal)
  const [isEditing, setIsEditing] = useState<boolean>(false);

  // History State (Global)
  const [history, setHistory] = useState<GenerationSession[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState<boolean>(false);

  const [error, setError] = useState<string | null>(null);

  // Helpers to get/set active workspace
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateActiveWorkspace = (updates: Partial<Workspace>) => {
    setWorkspaces(prev => prev.map(w => 
      w.id === activeWorkspaceId ? { ...w, ...updates } : w
    ));
  };

  useEffect(() => {
    const initAuth = async () => {
      try {
        const hasKey = await checkApiKey();
        setApiKeyReady(hasKey);
      } catch (e) {
        console.error("Failed to check API key status", e);
      }
    };
    initAuth();
  }, []);

  // Load/Save Workspaces & History
  useEffect(() => {
    try {
        const savedHistory = localStorage.getItem('app_history');
        if (savedHistory) setHistory(JSON.parse(savedHistory));

        const savedWorkspaces = localStorage.getItem('app_workspaces');
        if (savedWorkspaces) {
            const parsed = JSON.parse(savedWorkspaces);
            if (Array.isArray(parsed) && parsed.length > 0) {
                setWorkspaces(parsed);
                setActiveWorkspaceId(parsed[0].id);
            }
        }
    } catch (e) {
        console.error("Failed to load local data", e);
    }
  }, []);

  useEffect(() => {
    try {
        localStorage.setItem('app_history', JSON.stringify(history));
    } catch (e) {
        if (history.length > 10) {
            const trimmed = history.slice(0, 10);
            setHistory(trimmed);
        }
    }
  }, [history]);

  useEffect(() => {
    try {
        localStorage.setItem('app_workspaces', JSON.stringify(workspaces));
    } catch (e) {
        console.error("Failed to save workspaces", e);
    }
  }, [workspaces]);


  // --- Workspace Actions ---

  const addWorkspace = () => {
    // Cannot add while deleting
    if (isDeleteMode) return; 

    const newWs = createNewWorkspace(workspaces.length);
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  const removeWorkspace = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (workspaces.length === 1) return; // Prevent deleting last one

    const newWorkspaces = workspaces.filter(w => w.id !== id);
    setWorkspaces(newWorkspaces);
    if (activeWorkspaceId === id) {
        setActiveWorkspaceId(newWorkspaces[0].id);
    }
  };

  const handleNameEdit = (id: string, newName: string) => {
      setWorkspaces(prev => prev.map(w => w.id === id ? { ...w, name: newName } : w));
  };

  // --- Bulk Delete Logic ---

  const toggleDeleteMode = () => {
      setIsDeleteMode(!isDeleteMode);
      setDeleteSelection(new Set()); // Reset selection when toggling
  };

  const toggleTabSelection = (id: string) => {
      const newSet = new Set(deleteSelection);
      if (newSet.has(id)) {
          newSet.delete(id);
      } else {
          newSet.add(id);
      }
      setDeleteSelection(newSet);
  };

  const confirmBulkDelete = () => {
      if (deleteSelection.size === 0) {
          setIsDeleteMode(false);
          return;
      }

      if (!confirm(`Delete ${deleteSelection.size} dashboard(s)?`)) return;

      let newWorkspaces = workspaces.filter(w => !deleteSelection.has(w.id));

      // If we deleted everything, create a fresh one
      if (newWorkspaces.length === 0) {
          newWorkspaces = [createNewWorkspace(0)];
      }

      setWorkspaces(newWorkspaces);

      // If the active workspace was deleted, verify active ID
      if (deleteSelection.has(activeWorkspaceId)) {
          setActiveWorkspaceId(newWorkspaces[0].id);
      }

      setIsDeleteMode(false);
      setDeleteSelection(new Set());
  };


  // --- Logic ---

  const handleConnectKey = async () => {
    try {
      await promptForApiKey();
      setApiKeyReady(true);
      setError(null);
    } catch (e) {
      setError("Failed to connect API Key.");
    }
  };

  const activeImage = activeWorkspace.generatedBatch.find(img => img.id === activeWorkspace.selectedImageId) || null;

  const addToHistory = (batch: GeneratedImage[], currentWs: Workspace) => {
      const newSession: GenerationSession = {
          id: Date.now().toString(),
          prompt: currentWs.prompt,
          images: batch,
          timestamp: Date.now(),
          config: { ...currentWs.config }
      };
      setHistory(prev => [newSession, ...prev]);
  };

  const handleSelectSession = (session: GenerationSession) => {
      // Load session into active workspace
      updateActiveWorkspace({
          prompt: session.prompt,
          config: session.config,
          generatedBatch: session.images,
          selectedImageId: session.images.length > 0 ? session.images[0].id : null,
          status: 'success' // restore as success
      });
      setIsEditing(false);
  };

  const handleClearHistory = () => {
      if (confirm("Are you sure?")) {
          setHistory([]);
          localStorage.removeItem('app_history');
      }
  };

  const handleRemixUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = async (event) => {
          const result = event.target?.result as string;
          updateActiveWorkspace({ remixImage: result });

          // Auto analyze
          try {
             const description = await describeImage(result);
             updateActiveWorkspace({ prompt: description });
          } catch (err) {
              setError("Could not analyze image.");
          }
      };
      reader.readAsDataURL(file);
  };

  const handleGenerate = async () => {
    if (!activeWorkspace.prompt.trim()) {
      setError("Please enter a prompt.");
      return;
    }

    if (!apiKeyReady) {
        await handleConnectKey();
        return;
    }

    // Set Status: Generating (Orange)
    updateActiveWorkspace({ 
        isGenerating: true, 
        status: 'generating',
        generatedBatch: [], 
        selectedImageId: null 
    });

    setIsEditing(false);
    setError(null);

    const successfulImages: GeneratedImage[] = [];
    const promptTasks = Array(activeWorkspace.config.batchSize).fill(activeWorkspace.prompt);

    try {
      const promises = promptTasks.map(async (taskPrompt, index) => {
        try {
          let imageUrl = "";
          if (activeWorkspace.activeTab === 'remix' && activeWorkspace.remixImage) {
              imageUrl = await generateRemix(activeWorkspace.remixImage, taskPrompt, activeWorkspace.remixConfig, activeWorkspace.config);
          } else {
              imageUrl = await generateImageFromPrompt(taskPrompt, activeWorkspace.config);
          }

          const newImg: GeneratedImage = {
            id: `${Date.now()}-${index}`,
            url: imageUrl,
            prompt: taskPrompt,
            config: { ...activeWorkspace.config },
            timestamp: Date.now()
          };

          // Functional update to avoid closure staleness issues with async map
          setWorkspaces(prev => prev.map(w => {
              if (w.id === activeWorkspaceId) {
                  const updatedBatch = [...w.generatedBatch, newImg];
                  return {
                      ...w,
                      generatedBatch: updatedBatch,
                      selectedImageId: updatedBatch.length === 1 ? newImg.id : w.selectedImageId
                  };
              }
              return w;
          }));

          successfulImages.push(newImg);
        } catch (e) {
          console.error(`Prompt "${taskPrompt}" failed:`, e);
        }
      });

      await Promise.allSettled(promises);

      if (successfulImages.length === 0) {
        throw new Error("Failed to generate any images. Check your connection or API key.");
      }

      // Set Status: Success (Green)
      updateActiveWorkspace({ isGenerating: false, status: 'success' });
      addToHistory(successfulImages, activeWorkspace);

    } catch (err: any) {
      setError(err.message || "Something went wrong.");
      // Set Status: Error (Red)
      updateActiveWorkspace({ isGenerating: false, status: 'error' });
    }
  };

  // Helper to get tab color class based on status and active state
  const getTabColorClass = (ws: Workspace, isActive: boolean) => {
      // Logic overrides if in Delete Mode and Selected
      if (isDeleteMode && deleteSelection.has(ws.id)) {
          return 'border-red-500 bg-red-900/30 text-red-300';
      }

      if (ws.status === 'generating') return 'border-amber-500 text-amber-500 bg-amber-500/10 animate-pulse';
      if (ws.status === 'error') return isActive ? 'border-red-500 text-red-500 bg-slate-800' : 'border-red-500/50 text-red-700 bg-red-900/10';

      // Success state (Green)
      if (ws.status === 'success') {
          return isActive 
            ? 'border-emerald-500 text-emerald-500 bg-slate-800' 
            : 'border-emerald-500/50 text-emerald-600 bg-emerald-900/10 hover:text-emerald-500';
      }

      // Idle / Default state
      return isActive 
        ? 'border-indigo-500 bg-slate-800/50 text-white' 
        : 'border-transparent text-slate-400 hover:text-slate-200 hover:bg-slate-800/30';
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 pb-12 font-sans overflow-x-hidden flex flex-col">
      <header className="border-b border-slate-800 bg-[#0f172a]/95 z-30 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <span className="text-white font-bold text-lg">N</span>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">
              Nano Banana Pro
            </h1>
          </div>

          <div className="hidden md:flex space-x-1 bg-slate-800/50 p-1 rounded-lg border border-slate-700">
             <button onClick={() => updateActiveWorkspace({ activeTab: 'text-to-image' })} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeWorkspace.activeTab === 'text-to-image' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Text to Image
             </button>
             <button onClick={() => updateActiveWorkspace({ activeTab: 'remix' })} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeWorkspace.activeTab === 'remix' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Image Remix
             </button>
          </div>

          <div className="flex items-center gap-3">
            {!apiKeyReady ? (
              <Button onClick={handleConnectKey} variant="secondary" className="text-xs">Connect API Key</Button>
            ) : (
              <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-xs font-medium text-emerald-500 hidden sm:inline">System Ready</span>
              </div>
            )}
            <button onClick={() => setIsHistoryOpen(true)} className="p-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-300 transition relative">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      {/* Dashboard Tabs */}
      <div className={`border-b sticky top-0 z-20 transition-colors duration-300 ${isDeleteMode ? 'bg-red-950/20 border-red-900/50' : 'bg-[#0f172a] border-slate-800'}`}>
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex items-end gap-1 overflow-x-auto no-scrollbar">
              {workspaces.map((ws) => (
                  <div 
                    key={ws.id}
                    onClick={() => {
                        if (isDeleteMode) {
                            toggleTabSelection(ws.id);
                        } else {
                            setActiveWorkspaceId(ws.id);
                        }
                    }}
                    className={`
                        group relative flex items-center gap-2 px-4 py-2.5 min-w-[140px] max-w-[200px] cursor-pointer border-b-2 transition-all select-none
                        ${getTabColorClass(ws, activeWorkspaceId === ws.id)}
                    `}
                  >
                      {/* Checkbox for Delete Mode */}
                      {isDeleteMode && (
                        <div className={`w-4 h-4 rounded border flex items-center justify-center transition-colors ${deleteSelection.has(ws.id) ? 'bg-red-500 border-red-500' : 'border-slate-500'}`}>
                            {deleteSelection.has(ws.id) && (
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-white" viewBox="0 0 20 20" fill="currentColor">
                                    <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                                </svg>
                            )}
                        </div>
                      )}

                      {editingNameId === ws.id ? (
                          <input 
                            autoFocus
                            type="text" 
                            className="bg-slate-900 border border-indigo-500 rounded px-1 py-0.5 text-xs w-full outline-none text-white"
                            value={ws.name}
                            onChange={(e) => handleNameEdit(ws.id, e.target.value)}
                            onBlur={() => setEditingNameId(null)}
                            onKeyDown={(e) => e.key === 'Enter' && setEditingNameId(null)}
                          />
                      ) : (
                        <span className="text-sm font-medium truncate flex-1 flex items-center gap-2" onDoubleClick={() => !isDeleteMode && setEditingNameId(ws.id)}>
                            {/* Status Icon Indicator (Only if not deleting) */}
                            {!isDeleteMode && (
                                <>
                                    {ws.status === 'generating' && <div className="w-2 h-2 rounded-full bg-amber-500 animate-bounce" />}
                                    {ws.status === 'success' && <div className="w-2 h-2 rounded-full bg-emerald-500" />}
                                    {ws.status === 'error' && <div className="w-2 h-2 rounded-full bg-red-500" />}
                                </>
                            )}
                            {ws.name}
                        </span>
                      )}

                      {/* Individual X button (Hidden in delete mode) */}
                      {!isDeleteMode && workspaces.length > 1 && (
                          <button 
                            onClick={(e) => removeWorkspace(e, ws.id)}
                            className={`opacity-0 group-hover:opacity-100 p-0.5 hover:bg-slate-700 hover:text-red-400 rounded-full transition ${activeWorkspaceId === ws.id ? 'opacity-50' : ''}`}
                          >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                                <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                              </svg>
                          </button>
                      )}
                  </div>
              ))}

              <div className="flex items-center ml-2 border-l border-slate-700 pl-2 gap-1 h-full py-2">
                {!isDeleteMode ? (
                    <>
                        <button 
                            onClick={addWorkspace}
                            className="p-2 text-slate-500 hover:text-indigo-400 hover:bg-indigo-500/10 rounded-lg transition"
                            title="New Dashboard"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                            </svg>
                        </button>

                        {workspaces.length > 0 && (
                            <button 
                                onClick={toggleDeleteMode}
                                className="p-2 text-slate-500 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition"
                                title="Select Dashboards to Delete"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                </svg>
                            </button>
                        )}
                    </>
                ) : (
                    <div className="flex items-center gap-2 animate-fade-in">
                        <span className="text-xs text-slate-400 mr-1">{deleteSelection.size} selected</span>
                        <button 
                            onClick={confirmBulkDelete}
                            disabled={deleteSelection.size === 0}
                            className={`text-xs px-3 py-1.5 rounded font-medium transition ${deleteSelection.size > 0 ? 'bg-red-600 text-white hover:bg-red-500 shadow-lg shadow-red-900/50' : 'bg-slate-800 text-slate-500 cursor-not-allowed'}`}
                        >
                            Delete Selected
                        </button>
                        <button 
                            onClick={toggleDeleteMode}
                            className="text-xs px-3 py-1.5 rounded bg-slate-800 text-slate-300 hover:bg-slate-700 transition"
                        >
                            Cancel
                        </button>
                    </div>
                )}
              </div>
          </div>
      </div>

      <HistorySidebar 
        isOpen={isHistoryOpen} 
        onClose={() => setIsHistoryOpen(false)} 
        history={history}
        onSelectSession={handleSelectSession}
        onClearHistory={handleClearHistory}
      />

      {/* Main Single Column Layout - Full Width - Active Workspace Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 animate-fade-in">

        {error && (
          <div className="mb-6 p-4 rounded-lg bg-red-900/20 border border-red-900/50 flex items-start gap-3">
            <div className="flex-1 text-sm text-red-200">{error}</div>
            <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">×</button>
          </div>
        )}

        {isEditing && activeImage ? (
            <div className="space-y-4">
                <div className="flex justify-between items-center mb-2">
                    <h2 className="text-lg font-semibold text-white">Editor Studio - {activeWorkspace.name}</h2>
                    <Button variant="ghost" onClick={() => setIsEditing(false)} className="text-xs">
                        Back to Results
                    </Button>
                </div>
                <ImageEditor 
                    imageUrl={activeImage.url} 
                    onSave={(url) => {
                         // Update image in the current batch
                         const updatedBatch = activeWorkspace.generatedBatch.map(img => 
                             img.id === activeWorkspace.selectedImageId ? {...img, url} : img
                         );
                         updateActiveWorkspace({ generatedBatch: updatedBatch });
                         setIsEditing(false);
                    }} 
                    onCancel={() => setIsEditing(false)} 
                />
            </div>
        ) : (
            <div className="space-y-8">
                {/* SECTION 1: RESULTS (Top - Full Width) */}
                <div className="space-y-6 pb-8 border-b border-slate-800">
                    {/* Main Display Area */}
                    <div className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800 shadow-2xl">
                        <ImageDisplay 
                            image={activeImage} 
                            isGenerating={activeWorkspace.isGenerating} 
                            batchSize={activeWorkspace.config.batchSize}
                            onEdit={activeImage ? () => setIsEditing(true) : undefined}
                        />
                    </div>

                    {/* Gallery Grid */}
                    {(activeWorkspace.generatedBatch.length > 0 || activeWorkspace.isGenerating) && (
                        <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 lg:grid-cols-8 gap-3 animate-fade-in">
                            {activeWorkspace.generatedBatch.map((img) => (
                                <button
                                    key={img.id}
                                    onClick={() => updateActiveWorkspace({ selectedImageId: img.id })}
                                    className={`relative aspect-square rounded-lg overflow-hidden border-2 transition-all ${activeWorkspace.selectedImageId === img.id ? 'border-indigo-500 ring-2 ring-indigo-500/30' : 'border-slate-700 hover:border-slate-500'}`}
                                >
                                    <img src={img.url} alt="Result" className="w-full h-full object-cover" />
                                    {activeWorkspace.selectedImageId === img.id && (
                                        <div className="absolute inset-0 bg-indigo-500/10 pointer-events-none"></div>
                                    )}
                                </button>
                            ))}
                            {/* Loading Placeholders */}
                            {activeWorkspace.isGenerating && Array(Math.max(0, activeWorkspace.config.batchSize - activeWorkspace.generatedBatch.length)).fill(null).map((_, i) => (
                                <div key={i} className="aspect-square rounded-lg bg-slate-800/50 border-2 border-slate-700/50 border-dashed flex items-center justify-center animate-pulse">
                                    <div className="w-4 h-4 border-2 border-slate-600 border-t-transparent rounded-full animate-spin"></div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* SECTION 2: INPUTS (Bottom - Full Width) */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    <div className="lg:col-span-2 space-y-6">
                        {/* Remix Reference Upload */}
                        {activeWorkspace.activeTab === 'remix' && (
                            <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl space-y-4">
                                <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-wider">Reference Image</h3>
                                <div className="relative border-2 border-dashed border-slate-600 rounded-lg p-6 flex flex-col items-center justify-center bg-slate-900/50 hover:bg-slate-900 transition group">
                                    {activeWorkspace.remixImage ? (
                                        <div className="relative w-full aspect-video max-h-[300px]">
                                            <img src={activeWorkspace.remixImage} alt="Reference" className="w-full h-full object-contain rounded-md" />
                                            <button onClick={(e) => { e.preventDefault(); updateActiveWorkspace({ remixImage: null }); }} className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white rounded-full p-1 transition">×</button>
                                        </div>
                                    ) : (
                                        <>
                                            <p className="text-sm text-slate-400">Click to upload reference</p>
                                            <input type="file" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept="image/*" onChange={handleRemixUpload} />
                                        </>
                                    )}
                                </div>
                            </div>
                        )}

                        {/* Prompt Input Area */}
                        <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl h-full flex flex-col">
                            <div className="flex items-center justify-between mb-2">
                                <label htmlFor="prompt" className="block text-sm font-semibold text-indigo-400">
                                    {activeWorkspace.activeTab === 'remix' ? 'Description & Modifiers' : 'Creative Prompt'}
                                </label>
                            </div>
                            <div className="relative flex-1">
                                <textarea
                                    id="prompt"
                                    value={activeWorkspace.prompt}
                                    onChange={(e) => updateActiveWorkspace({ prompt: e.target.value })}
                                    placeholder="Describe your imagination..."
                                    className="w-full h-full min-h-[120px] bg-slate-900/80 border border-slate-700 rounded-lg p-3 text-slate-200 placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all resize-none text-sm leading-relaxed"
                                    disabled={activeWorkspace.isGenerating}
                                />
                            </div>
                        </div>
                    </div>

                    <div className="lg:col-span-1 flex flex-col gap-6">
                         {/* Settings Panel */}
                        <SettingsPanel 
                            config={activeWorkspace.config} 
                            onChange={(newCfg) => updateActiveWorkspace({ config: newCfg })} 
                            disabled={activeWorkspace.isGenerating} 
                        />

                        <Button 
                            onClick={handleGenerate} 
                            isLoading={activeWorkspace.isGenerating} 
                            disabled={activeWorkspace.activeTab === 'remix' && !activeWorkspace.remixImage}
                            className="w-full h-16 text-lg font-bold shadow-indigo-500/20"
                        >
                            {activeWorkspace.isGenerating 
                            ? `Generating...` 
                            : `Generate ${activeWorkspace.config.batchSize} Variations`}
                        </Button>
                    </div>
                </div>
            </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { AspectRatio, ImageSize, GenerationConfig, GeneratedImage, GenerationSession, RemixMode, RemixConfig, Workspace, WorkspaceStatus } from './types';
import { checkApiKey, promptForApiKey, generateImageFromPrompt, describeImage, generateRemix } from './services/geminiService';
import { SettingsPanel } from './components/SettingsPanel';
import { ImageDisplay } from './components/ImageDisplay';
import { ImageEditor } from './components/ImageEditor';
import { Button } from './components/Button';
import { HistorySidebar } from './components/HistorySidebar';

// Default configuration for new workspaces
const DEFAULT_CONFIG: GenerationConfig = {
  aspectRatio: AspectRatio.Square,
  imageSize: ImageSize.OneK,
  batchSize: 4
};

const DEFAULT_REMIX_CONFIG: RemixConfig = {
  creativity: 0.2,
  structureMatch: true,
  characterMatch: false
};

const createNewWorkspace = (index: number): Workspace => ({
  id: `ws-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
  name: `Dashboard ${index + 1}`,
  activeTab: 'text-to-image',
  prompt: '',
  isGenerating: false,
  status: 'idle',
  remixImage: null,
  remixConfig: { ...DEFAULT_REMIX_CONFIG },
  generatedBatch: [],
  selectedImageId: null,
  config: { ...DEFAULT_CONFIG }
});

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState<boolean>(false);

  // Workspace State
  const [workspaces, setWorkspaces] = useState<Workspace[]>([createNewWorkspace(0)]);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>(workspaces[0].id);
  const [editingNameId, setEditingNameId] = useState<string | null>(null);

  // Delete Mode State
  const [isDeleteMode, setIsDeleteMode] = useState<boolean>(false);
  const [deleteSelection, setDeleteSelection] = useState<Set<string>>(new Set());

  // Editor State (Global modal)
  const [isEditing, setIsEditing] = useState<boolean>(false);

  // History State (Global)
  const [history, setHistory] = useState<GenerationSession[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState<boolean>(false);

  const [error, setError] = useState<string | null>(null);

  // Helpers to get/set active workspace
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateActiveWorkspace = (updates: Partial<Workspace>) => {
    setWorkspaces(prev => prev.map(w => 
      w.id === activeWorkspaceId ? { ...w, ...updates } : w
    ));
  };

  useEffect(() => {
    const initAuth = async () => {
      try {
        const hasKey = await checkApiKey();
        setApiKeyReady(hasKey);
      } catch (e) {
        console.error("Failed to check API key status", e);
      }
    };
    initAuth();
  }, []);

  // Load/Save Workspaces & History
  useEffect(() => {
    try {
        const savedHistory = localStorage.getItem('app_history');
        if (savedHistory) setHistory(JSON.parse(savedHistory));

        const savedWorkspaces = localStorage.getItem('app_workspaces');
        if (savedWorkspaces) {
            const parsed = JSON.parse(savedWorkspaces);
            if (Array.isArray(parsed) && parsed.length > 0) {
                setWorkspaces(parsed);
                setActiveWorkspaceId(parsed[0].id);
            }
        }
    } catch (e) {
        console.error("Failed to load local data", e);
    }
  }, []);

  useEffect(() => {
    try {
        localStorage.setItem('app_history', JSON.stringify(history));
    } catch (e) {
        if (history.length > 10) {
            const trimmed = history.slice(0, 10);
            setHistory(trimmed);
        }
    }
  }, [history]);

  useEffect(() => {
    try {
        localStorage.setItem('app_workspaces', JSON.stringify(workspaces));
    } catch (e) {
        console.error("Failed to save workspaces", e);
    }
  }, [workspaces]);


  // --- Workspace Actions ---

  const addWorkspace = () => {
    if (isDeleteMode) return; 
    const newWs = createNewWorkspace(workspaces.length);
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  const removeWorkspace = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (workspaces.length === 1) return;
    const newWorkspaces = workspaces.filter(w => w.id !== id);
    setWorkspaces(newWorkspaces);
    if (activeWorkspaceId === id) {
        setActiveWorkspaceId(newWorkspaces[0].id);
    }
  };

  const handleNameEdit = (id: string, newName: string) => {
      setWorkspaces(prev => prev.map(w => w.id === id ? { ...w, name: newName } : w));
  };

  // --- Bulk Delete Logic ---

  const toggleDeleteMode = () => {
      setIsDeleteMode(!isDeleteMode);
      setDeleteSelection(new Set()); 
  };

  const toggleTabSelection = (id: string) => {
      const newSet = new Set(deleteSelection);
      if (newSet.has(id)) {
          newSet.delete(id);
      } else {
          newSet.add(id);
      }
      setDeleteSelection(newSet);
  };

  const confirmBulkDelete = () => {
      if (deleteSelection.size === 0) {
          setIsDeleteMode(false);
          return;
      }

      if (!confirm(`Bạn có chắc chắn muốn xóa ${deleteSelection.size} dashboard đã chọn?`)) return;

      let newWorkspaces = workspaces.filter(w => !deleteSelection.has(w.id));

      if (newWorkspaces.length === 0) {
          newWorkspaces = [createNewWorkspace(0)];
      }

      setWorkspaces(newWorkspaces);

      if (deleteSelection.has(activeWorkspaceId)) {
          setActiveWorkspaceId(newWorkspaces[0].id);
      }

      setIsDeleteMode(false);
      setDeleteSelection(new Set());
  };


  // --- Logic ---

  const handleConnectKey = async () => {
    try {
      await promptForApiKey();
      setApiKeyReady(true);
      setError(null);
    } catch (e) {
      setError("Không thể kết nối API Key.");
    }
  };

  const activeImage = activeWorkspace.generatedBatch.find(img => img.id === activeWorkspace.selectedImageId) || null;

  const addToHistory = (batch: GeneratedImage[], currentWs: Workspace) => {
      const newSession: GenerationSession = {
          id: Date.now().toString(),
          prompt: currentWs.prompt,
          images: batch,
          timestamp: Date.now(),
          config: { ...currentWs.config }
      };
      setHistory(prev => [newSession, ...prev]);
  };

  const handleSelectSession = (session: GenerationSession) => {
      updateActiveWorkspace({
          prompt: session.prompt,
          config: session.config,
          generatedBatch: session.images,
          selectedImageId: session.images.length > 0 ? session.images[0].id : null,
          status: 'success'
      });
      setIsEditing(false);
  };

  const handleClearHistory = () => {
      if (confirm("Xóa toàn bộ lịch sử?")) {
          setHistory([]);
          localStorage.removeItem('app_history');
      }
  };

  const handleRemixUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = async (event) => {
          const result = event.target?.result as string;
          updateActiveWorkspace({ remixImage: result });

          try {
             const description = await describeImage(result);
             updateActiveWorkspace({ prompt: description });
          } catch (err) {
              setError("Không thể phân tích ảnh.");
          }
      };
      reader.readAsDataURL(file);
  };

  const handleGenerate = async () => {
    if (!activeWorkspace.prompt.trim()) {
      setError("Vui lòng nhập prompt.");
      return;
    }

    if (!apiKeyReady) {
        await handleConnectKey();
        return;
    }

    updateActiveWorkspace({ 
        isGenerating: true, 
        status: 'generating',
        generatedBatch: [], 
        selectedImageId: null 
    });

    setIsEditing(false);
    setError(null);

    const successfulImages: GeneratedImage[] = [];
    const promptTasks = Array(activeWorkspace.config.batchSize).fill(activeWorkspace.prompt);

    try {
      const promises = promptTasks.map(async (taskPrompt, index) => {
        try {
          let imageUrl = "";
          if (activeWorkspace.activeTab === 'remix' && activeWorkspace.remixImage) {
              imageUrl = await generateRemix(activeWorkspace.remixImage, taskPrompt, activeWorkspace.remixConfig, activeWorkspace.config);
          } else {
              imageUrl = await generateImageFromPrompt(taskPrompt, activeWorkspace.config);
          }

          const newImg: GeneratedImage = {
            id: `${Date.now()}-${index}`,
            url: imageUrl,
            prompt: taskPrompt,
            config: { ...activeWorkspace.config },
            timestamp: Date.now()
          };

          setWorkspaces(prev => prev.map(w => {
              if (w.id === activeWorkspaceId) {
                  const updatedBatch = [...w.generatedBatch, newImg];
                  return {
                      ...w,
                      generatedBatch: updatedBatch,
                      selectedImageId: updatedBatch.length === 1 ? newImg.id : w.selectedImageId
                  };
              }
              return w;
          }));

          successfulImages.push(newImg);
        } catch (e) {
          console.error(`Prompt "${taskPrompt}" failed:`, e);
        }
      });

      await Promise.allSettled(promises);

      if (successfulImages.length === 0) {
        throw new Error("Không thể tạo ảnh. Vui lòng kiểm tra API Key hoặc kết nối.");
      }

      updateActiveWorkspace({ isGenerating: false, status: 'success' });
      addToHistory(successfulImages, activeWorkspace);

    } catch (err: any) {
      setError(err.message || "Đã xảy ra lỗi.");
      updateActiveWorkspace({ isGenerating: false, status: 'error' });
    }
  };

  const getTabColorClass = (ws: Workspace, isActive: boolean) => {
      if (isDeleteMode && deleteSelection.has(ws.id)) {
          return 'border-red-500 bg-red-900/30 text-red-300 ring-1 ring-red-500/50';
      }

      if (ws.status === 'generating') return 'border-amber-500 text-amber-500 bg-amber-500/10 animate-pulse';
      if (ws.status === 'error') return isActive ? 'border-red-500 text-red-500 bg-slate-800' : 'border-red-500/50 text-red-700 bg-red-900/10';

      if (ws.status === 'success') {
          return isActive 
            ? 'border-emerald-500 text-emerald-500 bg-slate-800 shadow-lg shadow-emerald-500/10' 
            : 'border-emerald-500/50 text-emerald-600 bg-emerald-900/10 hover:text-emerald-500';
      }

      return isActive 
        ? 'border-indigo-500 bg-slate-800/50 text-white' 
        : 'border-transparent text-slate-400 hover:text-slate-200 hover:bg-slate-800/30';
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 pb-12 font-sans overflow-x-hidden flex flex-col">
      <header className="border-b border-slate-800 bg-[#0f172a]/95 z-30 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <span className="text-white font-bold text-lg">N</span>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">
              Nano Banana Pro
            </h1>
          </div>

          <div className="hidden md:flex space-x-1 bg-slate-800/50 p-1 rounded-lg border border-slate-700">
             <button onClick={() => updateActiveWorkspace({ activeTab: 'text-to-image' })} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeWorkspace.activeTab === 'text-to-image' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Text to Image
             </button>
             <button onClick={() => updateActiveWorkspace({ activeTab: 'remix' })} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeWorkspace.activeTab === 'remix' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                Image Remix
             </button>
          </div>

          <div className="flex items-center gap-3">
            <Button onClick={handleConnectKey} variant="secondary" className="text-xs flex items-center gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" />
                </svg>
                {apiKeyReady ? "Đổi API Key" : "Kết nối API Key"}
            </Button>

            {apiKeyReady && (
                <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20">
                    <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                    <span className="text-xs font-medium text-emerald-500 hidden sm:inline">Ready</span>
                </div>
            )}

            <button onClick={() => setIsHistoryOpen(true)} className="p-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-300 transition relative">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      {/* Dashboard Tabs Container */}
      <div className={`border-b sticky top-0 z-20 transition-colors duration-300 ${isDeleteMode ? 'bg-red-950/40 border-red-900/50' : 'bg-[#0f172a] border-slate-800'}`}>
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex items-end gap-1 overflow-x-auto no-scrollbar py-2">
              {workspaces.map((ws) => (
                  <div 
                    key={ws.id}
                    onClick={() => {
                        if (isDeleteMode) {
                            toggleTabSelection(ws.id);
                        } else {
                            setActiveWorkspaceId(ws.id);
                        }
                    }}
                    className={`
                        group relative flex items-center gap-2 px-4 py-2 min-w-[140px] max-w-[200px] cursor-pointer border-b-2 transition-all rounded-t-lg select-none
                        ${getTabColorClass(ws, activeWorkspaceId === ws.id)}
                    `}
                  >
                      {/* Dashboard Checkbox (Delete Mode) */}
                      {isDeleteMode && (
                        <div className={`flex-shrink-0 w-4 h-4 rounded border flex items-center justify-center transition-all ${deleteSelection.has(ws.id) ? 'bg-red-500 border-red-500 scale-110' : 'border-slate-500 bg-slate-900/50'}`}>
                            {deleteSelection.has(ws.id) && (
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-white" viewBox="0 0 20 20" fill="currentColor">
                                    <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                                </svg>
                            )}
                        </div>
                      )}

                      {editingNameId === ws.id ? (
                          <input 
                            autoFocus
                            type="text" 
                            className="bg-slate-900 border border-indigo-500 rounded px-1 py-0.5 text-xs w-full outline-none text-white"
                            value={ws.name}
                            onChange={(e) => handleNameEdit(ws.id, e.target.value)}
                            onBlur={() => setEditingNameId(null)}
                            onKeyDown={(e) => e.key === 'Enter' && setEditingNameId(null)}
                          />
                      ) : (
                        <span className="text-sm font-medium truncate flex-1 flex items-center gap-2" onDoubleClick={() => !isDeleteMode && setEditingNameId(ws.id)}>
                            {!isDeleteMode && (
                                <>
                                    {ws.status === 'generating' && <div className="w-2 h-2 rounded-full bg-amber-500 animate-bounce" />}
                                    {ws.status === 'success' && <div className="w-2 h-2 rounded-full bg-emerald-500" />}
                                    {ws.status === 'error' && <div className="w-2 h-2 rounded-full bg-red-500" />}
                                </>
                            )}
                            {ws.name}
                        </span>
                      )}

                      {!isDeleteMode && workspaces.length > 1 && (
                          <button 
                            onClick={(e) => removeWorkspace(e, ws.id)}
                            className={`opacity-0 group-hover:opacity-100 p-0.5 hover:bg-slate-700 hover:text-red-400 rounded-full transition ${activeWorkspaceId === ws.id ? 'opacity-50' : ''}`}
                          >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                                <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                              </svg>
                          </button>
                      )}
                  </div>
              ))}

              <div className="flex items-center ml-2 border-l border-slate-700 pl-2 gap-1 h-10 self-center">
                {!isDeleteMode ? (
                    <>
                        <button 
                            onClick={addWorkspace}
                            className="p-2 text-slate-500 hover:text-indigo-400 hover:bg-indigo-500/10 rounded-lg transition"
                            title="Thêm Dashboard"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                            </svg>
                        </button>

                        <button 
                            onClick={toggleDeleteMode}
                            className="p-2 text-slate-500 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition"
                            title="Chọn Dashboard để xóa"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                            </svg>
                        </button>
                    </>
                ) : (
                    <div className="flex items-center gap-2 animate-fade-in bg-slate-900/80 px-3 py-1.5 rounded-full border border-red-500/30">
                        <span className="text-xs font-bold text-red-400">{deleteSelection.size} dashboard đã chọn</span>
                        <div className="h-4 w-px bg-slate-700"></div>
                        <button 
                            onClick={confirmBulkDelete}
                            disabled={deleteSelection.size === 0}
                            className={`text-[10px] px-3 py-1 rounded font-bold uppercase tracking-wider transition ${deleteSelection.size > 0 ? 'bg-red-600 text-white hover:bg-red-500 shadow-lg shadow-red-900/50' : 'bg-slate-800 text-slate-500 cursor-not-allowed'}`}
                        >
                            Xóa ngay
                        </button>
                        <button 
                            onClick={toggleDeleteMode}
                            className="text-[10px] px-3 py-1 rounded bg-slate-800 text-slate-300 hover:bg-slate-700 transition font-bold uppercase tracking-wider"
                        >
                            Hủy
                        </button>
                    </div>
                )}
              </div>
          </div>
      </div>

      <HistorySidebar 
        isOpen={isHistoryOpen} 
        onClose={() => setIsHistoryOpen(false)} 
        history={history}
        onSelectSession={handleSelectSession}
        onClearHistory={handleClearHistory}
      />

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 animate-fade-in">

        {error && (
          <div className="mb-6 p-4 rounded-lg bg-red-900/20 border border-red-900/50 flex items-start gap-3">
            <div className="flex-1 text-sm text-red-200">{error}</div>
            <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">×</button>
          </div>
        )}

        {isEditing && activeImage ? (
            <div className="space-y-4">
                <div className="flex justify-between items-center mb-2">
                    <h2 className="text-lg font-semibold text-white">Editor Studio - {activeWorkspace.name}</h2>
                    <Button variant="ghost" onClick={() => setIsEditing(false)} className="text-xs">
                        Quay lại
                    </Button>
                </div>
                <ImageEditor 
                    imageUrl={activeImage.url} 
                    onSave={(url) => {
                         const updatedBatch = activeWorkspace.generatedBatch.map(img => 
                             img.id === activeWorkspace.selectedImageId ? {...img, url} : img
                         );
                         updateActiveWorkspace({ generatedBatch: updatedBatch });
                         setIsEditing(false);
                    }} 
                    onCancel={() => setIsEditing(false)} 
                />
            </div>
        ) : (
            <div className="space-y-8">
                <div className="space-y-6 pb-8 border-b border-slate-800">
                    <div className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800 shadow-2xl">
                        <ImageDisplay 
                            image={activeImage} 
                            isGenerating={activeWorkspace.isGenerating} 
                            batchSize={activeWorkspace.config.batchSize}
                            onEdit={activeImage ? () => setIsEditing(true) : undefined}
                        />
                    </div>

                    {(activeWorkspace.generatedBatch.length > 0 || activeWorkspace.isGenerating) && (
                        <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 lg:grid-cols-8 gap-3 animate-fade-in">
                            {activeWorkspace.generatedBatch.map((img) => (
                                <button
                                    key={img.id}
                                    onClick={() => updateActiveWorkspace({ selectedImageId: img.id })}
                                    className={`relative aspect-square rounded-lg overflow-hidden border-2 transition-all ${activeWorkspace.selectedImageId === img.id ? 'border-indigo-500 ring-2 ring-indigo-500/30' : 'border-slate-700 hover:border-slate-500'}`}
                                >
                                    <img src={img.url} alt="Result" className="w-full h-full object-cover" />
                                    {activeWorkspace.selectedImageId === img.id && (
                                        <div className="absolute inset-0 bg-indigo-500/10 pointer-events-none"></div>
                                    )}
                                </button>
                            ))}
                            {activeWorkspace.isGenerating && Array(Math.max(0, activeWorkspace.config.batchSize - activeWorkspace.generatedBatch.length)).fill(null).map((_, i) => (
                                <div key={i} className="aspect-square rounded-lg bg-slate-800/50 border-2 border-slate-700/50 border-dashed flex items-center justify-center animate-pulse">
                                    <div className="w-4 h-4 border-2 border-slate-600 border-t-transparent rounded-full animate-spin"></div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    <div className="lg:col-span-2 space-y-6">
                        {activeWorkspace.activeTab === 'remix' && (
                            <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl space-y-4">
                                <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-wider">Reference Image</h3>
                                <div className="relative border-2 border-dashed border-slate-600 rounded-lg p-6 flex flex-col items-center justify-center bg-slate-900/50 hover:bg-slate-900 transition group">
                                    {activeWorkspace.remixImage ? (
                                        <div className="relative w-full aspect-video max-h-[300px]">
                                            <img src={activeWorkspace.remixImage} alt="Reference" className="w-full h-full object-contain rounded-md" />
                                            <button onClick={(e) => { e.preventDefault(); updateActiveWorkspace({ remixImage: null }); }} className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white rounded-full p-1 transition">×</button>
                                        </div>
                                    ) : (
                                        <>
                                            <p className="text-sm text-slate-400">Click to upload reference</p>
                                            <input type="file" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept="image/*" onChange={handleRemixUpload} />
                                        </>
                                    )}
                                </div>
                            </div>
                        )}

                        <div className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl p-5 shadow-xl h-full flex flex-col">
                            <div className="flex items-center justify-between mb-2">
                                <label htmlFor="prompt" className="block text-sm font-semibold text-indigo-400">
                                    {activeWorkspace.activeTab === 'remix' ? 'Mô tả & Biến đổi' : 'Creative Prompt'}
                                </label>
                            </div>
                            <div className="relative flex-1">
                                <textarea
                                    id="prompt"
                                    value={activeWorkspace.prompt}
                                    onChange={(e) => updateActiveWorkspace({ prompt: e.target.value })}
                                    placeholder="Mô tả ý tưởng của bạn..."
                                    className="w-full h-full min-h-[120px] bg-slate-900/80 border border-slate-700 rounded-lg p-3 text-slate-200 placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all resize-none text-sm leading-relaxed"
                                    disabled={activeWorkspace.isGenerating}
                                />
                            </div>
                        </div>
                    </div>

                    <div className="lg:col-span-1 flex flex-col gap-6">
                        <SettingsPanel 
                            config={activeWorkspace.config} 
                            onChange={(newCfg) => updateActiveWorkspace({ config: newCfg })} 
                            disabled={activeWorkspace.isGenerating} 
                        />

                        <Button 
                            onClick={handleGenerate} 
                            isLoading={activeWorkspace.isGenerating} 
                            disabled={activeWorkspace.activeTab === 'remix' && !activeWorkspace.remixImage}
                            className="w-full h-16 text-lg font-bold shadow-indigo-500/20"
                        >
                            {activeWorkspace.isGenerating 
                            ? `Đang tạo...` 
                            : `Tạo ${activeWorkspace.config.batchSize} biến thể`}
                        </Button>
                    </div>
                </div>
            </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Button } from './Button';
import { ImageFilters, Layer, BaseLayer, TextLayer, ImageLayer } from '../types';
import { editGeneratedImage, generateMask } from '../services/geminiService';

interface ImageEditorProps {
  imageUrl: string;
  onSave: (newUrl: string) => void;
  onCancel: () => void;
}

type EditorMode = 'design' | 'smart-edit';
type SmartTool = 'none' | 'fill' | 'erase';

export const ImageEditor: React.FC<ImageEditorProps> = ({ imageUrl, onSave, onCancel }) => {
  // --- State ---
  const [layers, setLayers] = useState<Layer[]>([]);
  const [selectedLayerId, setSelectedLayerId] = useState<string | null>(null);

  // History State
  const [history, setHistory] = useState<Layer[][]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Canvas Refs
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Smart Edit State (Generative Fill/Erase)
  const [smartTool, setSmartTool] = useState<SmartTool>('none');
  const [maskCanvas, setMaskCanvas] = useState<HTMLCanvasElement | null>(null);
  const [brushSize, setBrushSize] = useState(40);
  const [aiPrompt, setAiPrompt] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);

  // Dragging / Transform State
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [initialLayerState, setInitialLayerState] = useState<Partial<Layer> | null>(null);

  // --- History Management ---

  const recordHistory = (newLayers: Layer[]) => {
    // Slice history to current point (remove future redo steps if we branch)
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(newLayers);
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  };

  const undo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      setLayers(history[newIndex]);
    }
  };

  const redo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      setLayers(history[newIndex]);
    }
  };

  // Keyboard Shortcuts for Undo/Redo
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
        e.preventDefault();
        if (e.shiftKey) {
          redo();
        } else {
          undo();
        }
      }
      if ((e.metaKey || e.ctrlKey) && e.key === 'y') {
        e.preventDefault();
        redo();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [historyIndex, history]);

  // Initialize Base Layer
  useEffect(() => {
    // Only init if empty
    if (layers.length === 0) {
      const baseId = 'base-layer';
      const newLayer: BaseLayer = {
        id: baseId,
        type: 'base',
        url: imageUrl,
        visible: true,
        filters: { brightness: 100, contrast: 100, saturation: 100, grayscale: 0, sepia: 0, blur: 0 }
      };
      const initialLayers = [newLayer];
      setLayers(initialLayers);
      setSelectedLayerId(baseId);

      // Init History
      setHistory([initialLayers]);
      setHistoryIndex(0);
    }
  }, [imageUrl]);

  // Initialize Mask Canvas when base layer image loads
  useEffect(() => {
    const baseLayer = layers.find(l => l.type === 'base') as BaseLayer;
    if (baseLayer) {
        const img = new Image();
        img.src = baseLayer.url;
        img.onload = () => {
            if (!maskCanvas) {
                const mc = document.createElement('canvas');
                mc.width = img.naturalWidth;
                mc.height = img.naturalHeight;
                setMaskCanvas(mc);
            }
        };
    }
  }, [layers]);

  // --- Rendering Loop ---
  useEffect(() => {
    if (!canvasRef.current || layers.length === 0) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Get Base Layer for dimensions
    const baseLayer = layers.find(l => l.type === 'base') as BaseLayer;
    if (!baseLayer) return;

    const baseImg = new Image();
    baseImg.src = baseLayer.url;

    // We need to wait for the base image to allow sizing
    if (canvas.width !== baseImg.naturalWidth && baseImg.naturalWidth > 0) {
         canvas.width = baseImg.naturalWidth;
         canvas.height = baseImg.naturalHeight;
    }

    // Clear Canvas
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // --- Render Layers ---
    const renderPromises = layers.map((layer) => {
        return new Promise<void>((resolve) => {
            if (!layer.visible) { resolve(); return; }

            if (layer.type === 'base') {
                const img = new Image();
                img.src = layer.url;
                img.onload = () => {
                    ctx.save();
                    ctx.filter = `brightness(${layer.filters.brightness}%) contrast(${layer.filters.contrast}%) saturate(${layer.filters.saturation}%) grayscale(${layer.filters.grayscale}%) sepia(${layer.filters.sepia}%) blur(${layer.filters.blur}px)`;
                    ctx.drawImage(img, 0, 0);
                    ctx.restore();
                    resolve();
                };
                if (img.complete) img.onload(new Event('load') as any);
            } 
            else if (layer.type === 'image') {
                const img = new Image();
                img.src = layer.url;
                img.onload = () => {
                    ctx.save();
                    ctx.globalAlpha = layer.opacity;
                    ctx.translate(layer.x + layer.width / 2, layer.y + layer.height / 2);
                    ctx.rotate((layer.rotation * Math.PI) / 180);
                    ctx.drawImage(img, -layer.width / 2, -layer.height / 2, layer.width, layer.height);
                    ctx.restore();
                    resolve();
                };
                if (img.complete) img.onload(new Event('load') as any);
            } 
            else if (layer.type === 'text') {
                ctx.save();
                ctx.translate(layer.x, layer.y);
                ctx.rotate((layer.rotation * Math.PI) / 180);

                ctx.font = `${layer.fontWeight} ${layer.fontSize}px ${layer.fontFamily}`;
                ctx.textBaseline = 'top';

                if (layer.gradient?.enabled && layer.gradient.colors.length > 1) {
                    const measure = ctx.measureText(layer.text);
                    const width = measure.width;
                    const height = layer.fontSize; // Approx

                    const grad = layer.gradient.direction === 'horizontal'
                        ? ctx.createLinearGradient(0, 0, width, 0)
                        : ctx.createLinearGradient(0, 0, 0, height);

                    grad.addColorStop(0, layer.gradient.colors[0]);
                    grad.addColorStop(1, layer.gradient.colors[1]);
                    ctx.fillStyle = grad;
                } else {
                    ctx.fillStyle = layer.color;
                }

                ctx.fillText(layer.text, 0, 0);

                ctx.restore();
                resolve();
            }
        });
    });

    // Wait for all to draw then draw overlays
    Promise.all(renderPromises).then(() => {
        // Draw Smart Mask
        if (smartTool !== 'none' && maskCanvas) {
            ctx.save();
            ctx.globalAlpha = 0.6;
            ctx.drawImage(maskCanvas, 0, 0);
            ctx.restore();
        }

        // Draw Selection Indicators
        if (selectedLayerId && smartTool === 'none') {
            const layer = layers.find(l => l.id === selectedLayerId);
            if (layer && layer.visible) {
                ctx.save();
                ctx.strokeStyle = '#6366f1'; // Indigo 500
                ctx.lineWidth = 2;

                if (layer.type === 'image') {
                    // Calculate bounding box after rotation
                    ctx.translate(layer.x + layer.width/2, layer.y + layer.height/2);
                    ctx.rotate((layer.rotation * Math.PI) / 180);
                    ctx.strokeRect(-layer.width/2, -layer.height/2, layer.width, layer.height);

                    // Draw Handles
                    ctx.fillStyle = 'white';
                    ctx.fillRect(layer.width/2 - 5, layer.height/2 - 5, 10, 10); // Bottom Right Resize Handle
                } else if (layer.type === 'text') {
                     // Approximate text box
                    ctx.translate(layer.x, layer.y);
                    ctx.rotate((layer.rotation * Math.PI) / 180);

                    // Measure text for better box
                    ctx.font = `${layer.fontWeight} ${layer.fontSize}px ${layer.fontFamily}`;
                    const m = ctx.measureText(layer.text);
                    const h = layer.fontSize; 

                    ctx.strokeRect(-5, -5, m.width + 10, h + 10);
                }
                ctx.restore();
            }
        }
    });

  }, [layers, selectedLayerId, smartTool, maskCanvas, isProcessing]);


  // --- Tools & Actions ---

  const addTextLayer = () => {
    if (!canvasRef.current) return;
    const newLayer: TextLayer = {
        id: `text-${Date.now()}`,
        type: 'text',
        text: 'Double Click to Edit',
        x: canvasRef.current.width / 2 - 100,
        y: canvasRef.current.height / 2,
        width: 300,
        height: 60,
        rotation: 0,
        fontSize: 60,
        fontFamily: 'Inter, sans-serif',
        fontWeight: 'bold',
        color: '#ffffff',
        visible: true
    };
    const newLayers = [...layers, newLayer];
    setLayers(newLayers);
    setSelectedLayerId(newLayer.id);
    recordHistory(newLayers);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = async (event) => {
          const result = event.target?.result as string;

          setIsProcessing(true);
          try {
              // 1. Get Mask
              const maskDataUrl = await generateMask(result);

              // 2. Apply Mask Client Side (Remove BG)
              const processedImage = await removeBackgroundWithMask(result, maskDataUrl);

              const img = new Image();
              img.src = processedImage;
              img.onload = () => {
                   const newLayer: ImageLayer = {
                       id: `img-${Date.now()}`,
                       type: 'image',
                       url: processedImage,
                       x: 50,
                       y: 50,
                       width: img.naturalWidth,
                       height: img.naturalHeight,
                       rotation: 0,
                       visible: true,
                       opacity: 1
                   };
                   const newLayers = [...layers, newLayer];
                   setLayers(newLayers);
                   setSelectedLayerId(newLayer.id);
                   recordHistory(newLayers);
              };

          } catch (error) {
              console.error("BG Removal failed", error);
              // Fallback: Add original
              const newLayer: ImageLayer = {
                  id: `img-${Date.now()}`,
                  type: 'image',
                  url: result,
                  x: 50, y: 50, width: 300, height: 300, rotation: 0, visible: true, opacity: 1
              };
              const newLayers = [...layers, newLayer];
              setLayers(newLayers);
              recordHistory(newLayers);
          } finally {
              setIsProcessing(false);
          }
      };
      reader.readAsDataURL(file);
  };

  const removeBackgroundWithMask = (original: string, mask: string): Promise<string> => {
      return new Promise((resolve) => {
          const c = document.createElement('canvas');
          const ctx = c.getContext('2d');
          const img = new Image();
          const maskImg = new Image();

          let loaded = 0;
          const onLoad = () => {
              loaded++;
              if (loaded === 2 && ctx) {
                  c.width = img.width;
                  c.height = img.height;

                  // Draw Original
                  ctx.drawImage(img, 0, 0);

                  // Get Data
                  const imgData = ctx.getImageData(0, 0, c.width, c.height);

                  // Draw Mask on temp
                  const maskC = document.createElement('canvas');
                  maskC.width = c.width;
                  maskC.height = c.height;
                  const maskCtx = maskC.getContext('2d');
                  maskCtx?.drawImage(maskImg, 0, 0);
                  const maskData = maskCtx?.getImageData(0, 0, c.width, c.height);

                  if (maskData) {
                    for (let i = 0; i < imgData.data.length; i += 4) {
                        const brightness = (maskData.data[i] + maskData.data[i+1] + maskData.data[i+2]) / 3;
                        if (brightness < 50) {
                            imgData.data[i+3] = 0; 
                        } else {
                            imgData.data[i+3] = Math.min(255, brightness * 2); 
                        }
                    }
                  }

                  ctx.putImageData(imgData, 0, 0);
                  resolve(c.toDataURL());
              }
          };

          img.onload = onLoad;
          maskImg.onload = onLoad;
          img.src = original;
          maskImg.src = mask;
      });
  };

  const handleAutoBlend = async () => {
    if (!canvasRef.current || !selectedLayerId) return;

    // We need to bake the composition into a single image
    // Then replace the Base Layer with this new image
    // And hide/remove the Product Layer

    setIsProcessing(true);
    try {
        const dataUrl = canvasRef.current.toDataURL('image/png');

        const prompt = "The image is a composite of a background and a pasted product. Harmonize the lighting, shadows, and color tone of the pasted object to make it look photorealistic and naturally integrated into the scene. Do NOT change the product's shape, text, or details.";

        const resultUrl = await editGeneratedImage(dataUrl, prompt);

        // Update Layers
        const newLayers = layers.map(l => {
            if (l.type === 'base') {
                return { ...l, url: resultUrl };
            }
            if (l.id === selectedLayerId) {
                // Hide the product layer as it's now baked in
                return { ...l, visible: false };
            }
            return l;
        }) as Layer[];

        setLayers(newLayers);
        setSelectedLayerId(layers.find(l => l.type === 'base')?.id || null);
        recordHistory(newLayers);

    } catch (e) {
        console.error("Auto Blend Failed", e);
        alert("Failed to blend product. Please try again.");
    } finally {
        setIsProcessing(false);
    }
  };

  const handleSmartEdit = async () => {
      if (!maskCanvas || !canvasRef.current) return;

      const baseLayer = layers.find(l => l.type === 'base') as BaseLayer;
      if (!baseLayer) return;

      setIsProcessing(true);
      try {
          // Prepare composition for model
          const tempCanvas = document.createElement('canvas');
          tempCanvas.width = canvasRef.current.width;
          tempCanvas.height = canvasRef.current.height;
          const ctx = tempCanvas.getContext('2d');

          if (ctx) {
             const img = new Image();
             img.src = baseLayer.url;
             await new Promise(r => img.onload = r);
             ctx.drawImage(img, 0, 0);

             // Draw the Mask on top for the API with specific color hint
             ctx.globalAlpha = 0.5;
             ctx.drawImage(maskCanvas, 0, 0);
             ctx.globalAlpha = 1.0;
          }

          const base64Input = tempCanvas.toDataURL('image/png');

          // Tailor Prompt based on color
          const prompt = smartTool === 'erase'
            ? "Remove the object covered in RED. Fill background seamlessly matching the surrounding texture."
            : `Replace the GREEN area with: ${aiPrompt}`;

          const resultUrl = await editGeneratedImage(base64Input, prompt);

          // Update Base Layer
          const newLayers = layers.map(l => l.type === 'base' ? { ...l, url: resultUrl } : l);
          setLayers(newLayers as Layer[]);
          recordHistory(newLayers as Layer[]);

          // Clear Mask
          const maskCtx = maskCanvas.getContext('2d');
          maskCtx?.clearRect(0, 0, maskCanvas.width, maskCanvas.height);
          setSmartTool('none');

      } catch (e) {
          console.error(e);
      } finally {
          setIsProcessing(false);
      }
  };

  const deleteLayer = () => {
       const newLayers = layers.filter(l => l.id !== selectedLayerId);
       setLayers(newLayers);
       setSelectedLayerId(null);
       recordHistory(newLayers);
  };

  const toggleVisibility = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const newLayers = layers.map(l => l.id === id ? { ...l, visible: !l.visible } : l) as Layer[];
    setLayers(newLayers);
    recordHistory(newLayers);
  };

  // --- Interaction ---

  const getCanvasCoords = (e: React.MouseEvent) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;
    return {
        x: (e.clientX - rect.left) * scaleX,
        y: (e.clientY - rect.top) * scaleY
    };
  };

  const onMouseDown = (e: React.MouseEvent) => {
      const { x, y } = getCanvasCoords(e);

      if (smartTool !== 'none') {
          setIsDragging(true); // Reusing drag state for painting
          drawMask(x, y);
          return;
      }

      // Hit Test for Layers (Reverse order to select top-most)
      let hitLayerId: string | null = null;
      for (let i = layers.length - 1; i >= 0; i--) {
          const l = layers[i];
          if (!l.visible || l.type === 'base') continue;

          // Simple Bounding Box Check (ignoring rotation for simplicity in hit test)
          if (x >= l.x && x <= l.x + l.width && y >= l.y && y <= l.y + l.height) {
              hitLayerId = l.id;
              break;
          }
      }

      if (hitLayerId) {
          setSelectedLayerId(hitLayerId);
          setIsDragging(true);
          setDragStart({ x, y });
          const l = layers.find(lay => lay.id === hitLayerId);
          setInitialLayerState(l || null);
      } else {
          setSelectedLayerId(layers.find(l => l.type === 'base')?.id || null);
      }
  };

  const onMouseMove = (e: React.MouseEvent) => {
      const { x, y } = getCanvasCoords(e);

      if (smartTool !== 'none' && isDragging) {
          drawMask(x, y);
          return;
      }

      if (isDragging && selectedLayerId && initialLayerState) {
          const dx = x - dragStart.x;
          const dy = y - dragStart.y;

          setLayers(prev => prev.map(l => {
              if (l.id === selectedLayerId && (l.type === 'text' || l.type === 'image')) {
                  const initState = initialLayerState as TextLayer | ImageLayer;
                  return { 
                      ...l, 
                      x: (initState.x || 0) + dx, 
                      y: (initState.y || 0) + dy 
                  };
              }
              return l;
          }));
      }
  };

  const onMouseUp = () => {
      // Check if a drag operation actually changed properties before saving history
      // Fix: Add explicit type casting and type checks to ensure x and y properties exist
      if (isDragging && initialLayerState && selectedLayerId) {
        const currentLayer = layers.find(l => l.id === selectedLayerId);
        if (currentLayer && (currentLayer.type === 'text' || currentLayer.type === 'image')) {
            const castLayer = currentLayer as TextLayer | ImageLayer;
            const castInitial = initialLayerState as Partial<TextLayer | ImageLayer>;
            if (castLayer.x !== castInitial.x || castLayer.y !== castInitial.y) {
                 recordHistory(layers);
            }
        }
      }
      setIsDragging(false);
      setInitialLayerState(null);
  };

  const drawMask = (x: number, y: number) => {
      if (!maskCanvas) return;
      const ctx = maskCanvas.getContext('2d');
      if (!ctx) return;

      // Paint Green for Fill, Red for Erase
      ctx.fillStyle = smartTool === 'erase' ? 'rgba(239, 68, 68, 1)' : 'rgba(34, 197, 94, 1)';
      ctx.beginPath();
      ctx.arc(x, y, brushSize, 0, Math.PI * 2);
      ctx.fill();
      // Trigger re-render
      setIsProcessing(prev => !prev); // Hack force update
  };

  // --- Final Save ---
  const handleFinalSave = () => {
      if (!canvasRef.current) return;
      // To get a clean output without UI overlays, select nothing before save
      setSelectedLayerId(null);
      setTimeout(() => {
          if(!canvasRef.current) return;
          const data = canvasRef.current.toDataURL('image/png');
          onSave(data);
      }, 50);
  };

  // --- UI Helpers ---
  const selectedLayer = layers.find(l => l.id === selectedLayerId);

  const updateSelectedLayer = (updates: Partial<Layer>) => {
      setLayers(prev => prev.map(l => l.id === selectedLayerId ? { ...l, ...updates } as Layer : l));
  };

  // Call this on blur/mouseup of inputs to save history
  const commitPropertyChange = () => {
      recordHistory(layers);
  };

  return (
    <div className="flex h-[85vh] bg-slate-900 rounded-xl overflow-hidden border border-slate-700">
       {/* Left Toolbar - Tools */}
       <div className="w-16 bg-slate-800 border-r border-slate-700 flex flex-col items-center py-4 space-y-4">
            <button onClick={addTextLayer} className="p-2 bg-slate-700 rounded hover:bg-indigo-600 transition text-white group relative" title="Add Text">
                <span className="text-lg font-serif font-bold">T</span>
                <span className="absolute left-14 bg-black text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">Add Text</span>
            </button>
            <label className="p-2 bg-slate-700 rounded hover:bg-emerald-600 transition text-white cursor-pointer group relative" title="Add Product">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                </svg>
                <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
                <span className="absolute left-14 bg-black text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">Add Product</span>
            </label>
            <div className="w-8 h-px bg-slate-600 my-2"></div>
            <button 
                onClick={() => setSmartTool(smartTool === 'fill' ? 'none' : 'fill')} 
                className={`p-2 rounded transition text-white group relative ${smartTool === 'fill' ? 'bg-emerald-600' : 'bg-slate-700 hover:bg-emerald-600'}`}
                title="Generative Fill"
            >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                </svg>
                <span className="absolute left-14 bg-black text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">Generative Fill</span>
            </button>
            <button 
                onClick={() => setSmartTool(smartTool === 'erase' ? 'none' : 'erase')} 
                className={`p-2 rounded transition text-white group relative ${smartTool === 'erase' ? 'bg-red-600' : 'bg-slate-700 hover:bg-red-600'}`}
                title="Magic Eraser"
            >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
                 <span className="absolute left-14 bg-black text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">Magic Eraser</span>
            </button>
       </div>

       {/* Main Canvas Area */}
       <div className="flex-1 bg-slate-950 relative overflow-auto flex items-center justify-center p-8" ref={containerRef}>
