import { GoogleGenAI, Type } from "@google/genai";
import { GenerationConfig, RemixConfig } from "../types";

// Fixed: Removed conflicting global Window interface augmentation.
// Using type assertion (window as any) to access aistudio properties to avoid type conflicts with existing definitions.

export const checkApiKey = async (): Promise<boolean> => {
  const win = window as any;
  if (win.aistudio && win.aistudio.hasSelectedApiKey) {
    return await win.aistudio.hasSelectedApiKey();
  }
  return false;
};

export const promptForApiKey = async (): Promise<void> => {
  const win = window as any;
  if (win.aistudio && win.aistudio.openSelectKey) {
    await win.aistudio.openSelectKey();
  } else {
    console.warn("AI Studio API key selection not available in this environment.");
  }
};

export const generateImageFromPrompt = async (
  prompt: string,
  config: GenerationConfig
): Promise<string> => {
  // Ensure we have a fresh client with the latest environment key
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found. Please select a key.");
  }

  const ai = new GoogleGenAI({ apiKey });

  // Use the specific model requested: Nano Banana Pro maps to gemini-3-pro-image-preview
  const model = "gemini-3-pro-image-preview";

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: config.aspectRatio,
          imageSize: config.imageSize,
        },
      },
    });

    // Parse response to find the image part
    if (response.candidates && response.candidates[0].content.parts) {
        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData && part.inlineData.data) {
                const base64Data = part.inlineData.data;
                const mimeType = part.inlineData.mimeType || "image/png";
                return `data:${mimeType};base64,${base64Data}`;
            }
        }
    }

    throw new Error("No image data found in the response.");
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    // Handle the specific "Requested entity was not found" error which implies invalid key selection
    if (error.message && error.message.includes("Requested entity was not found")) {
         // Reset key and prompt again according to instructions
         await promptForApiKey();
         throw new Error("API Key Error: Please re-select your API key.");
    }
    throw error;
  }
};

/**
 * Analyzes an image to provide a semantic description (prompt).
 * Used for the Remix workflow.
 */
export const describeImage = async (base64Image: string): Promise<string> => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API Key not found");

    const ai = new GoogleGenAI({ apiKey });
    // Use gemini-3-flash-preview for analysis tasks as it's the recommended multimodal task model
    const model = 'gemini-3-flash-preview';

    const base64Data = base64Image.replace(/^data:image\/\w+;base64,/, "");

    try {
      const response = await ai.models.generateContent({
        model,
        contents: {
          parts: [
            {
              inlineData: {
                mimeType: 'image/png',
                data: base64Data
              }
            },
            { text: "Analyze this image and describe it in extreme detail. Include the subject, outfit, colors, lighting conditions, camera angle, and background style. The output should be a direct image generation prompt." }
          ]
        }
      });

      return response.text || "An image";
    } catch (error: any) {
      console.error("Analysis Error:", error);
      if (error.message && error.message.includes("Requested entity was not found")) {
          await promptForApiKey();
      }
      return "An image suitable for remixing.";
    }
};

/**
 * Generates a variation of an image based on a reference and prompt.
 * Simulates "Remix" behavior via prompt engineering and multimodal input.
 */
export const generateRemix = async (
    referenceImage: string,
    userPrompt: string,
    remixConfig: RemixConfig,
    genConfig: GenerationConfig
): Promise<string> => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API Key not found");

    const ai = new GoogleGenAI({ apiKey });
    const model = 'gemini-3-pro-image-preview'; // High quality model for remix
    const base64Data = referenceImage.replace(/^data:image\/\w+;base64,/, "");

    // Detailed System Instruction for Similarity vs Creativity
    let roleInstruction = "";

    if (remixConfig.creativity < 0.4) {
        // High Fidelity / Similarity Mode
        roleInstruction = `
            TASK: Recreate the attached reference image with extremely high fidelity.
            INSTRUCTIONS:
            1. STRICTLY ADHERE to the composition, pose, camera angle, and lighting of the reference image.
            2. The output should look like a "twin" or a "variation" of the original.
            3. Use the user provided text to understand the content, but prioritize the VISUAL INPUT for structure.
            4. Fix any artifacts or blurriness from the original, making it high resolution (4K).
        `;
    } else if (remixConfig.creativity < 0.7) {
        // Variation Mode
        roleInstruction = `
            TASK: Create a stylistic variation of the reference image.
            INSTRUCTIONS:
            1. Keep the main subject and general layout (composition) of the reference image.
            2. You may change the art style, lighting atmosphere, or background details based on the prompt.
            3. The output should be recognizable as being derived from the input.
        `;
    } else {
        // Reimagine Mode
        roleInstruction = `
            TASK: Reimagine the concept of the reference image.
            INSTRUCTIONS:
            1. Use the reference image as loose inspiration for color and vibe.
            2. You are free to change the composition and pose significantly.
            3. Create a brand new unique artwork based on the text prompt.
        `;
    }

    if (remixConfig.structureMatch) {
        roleInstruction += " \nCRITICAL: You MUST preserve the exact geometry and object placement of the reference image (ControlNet-like structure lock).";
    }

    if (remixConfig.characterMatch) {
        roleInstruction += " \nCRITICAL: You MUST preserve the facial identity and features of the character from the reference image.";
    }

    const fullPrompt = `${roleInstruction} \n\n User Prompt Description: ${userPrompt}`;

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: {
                parts: [
                    {
                        inlineData: {
                            mimeType: 'image/png',
                            data: base64Data
                        }
                    },
                    { text: fullPrompt }
                ],
            },
            config: {
                imageConfig: {
                    aspectRatio: genConfig.aspectRatio,
                    imageSize: genConfig.imageSize,
                },
            },
        });

        if (response.candidates && response.candidates[0].content.parts) {
            for (const part of response.candidates[0].content.parts) {
                if (part.inlineData && part.inlineData.data) {
                    const mimeType = part.inlineData.mimeType || "image/png";
                    return `data:${mimeType};base64,${part.inlineData.data}`;
                }
            }
        }

        throw new Error("No image data found in remix response.");

    } catch (error: any) {
        console.error("Remix Error:", error);
        if (error.message && error.message.includes("Requested entity was not found")) {
            await promptForApiKey();
            throw new Error("API Key Error: Please re-select your API key.");
        }
        throw error;
    }
};

